import { useState, useEffect, useRef, useCallback, Component } from 'react';
import * as LWC from 'lightweight-charts';
const { createChart, CandlestickSeries, HistogramSeries, ColorType, CrosshairMode } = LWC;
import { api } from '../utils/api';

/* ── Design tokens ─────────────────────────────────────────────── */
const colors = {
  bg: '#0D1117',
  surface: '#161B22',
  surface2: '#111A24',
  border: '#1F2A37',
  textPrimary: '#E5E7DB',
  textSecondary: '#90A3AF',
  green: '#3FB950',
  red: '#F85149',
  blue: '#58A6FF',
  amber: '#D29922',
  purple: '#BC8CFF',
  crosshair: '#58A6FF',
  grid: '#111A24',
  volumeUp: 'rgba(63,185,80,0.3)',
  volumeDown: 'rgba(248,81,73,0.3)',
};

const mono = "'JetBrains Mono', monospace";

const TIMEFRAMES = ['1m', '5m', '15m', '1h', '4h', '1D', '1W'];
const DEFAULT_SYMBOLS = ['SPY', 'AAPL', 'MSFT', 'TSLA', 'NVDA', 'AMD'];

/* ── Layout definitions ────────────────────────────────────────── */
const LAYOUTS = [
  { id: '1x1', label: '1x1', cols: 1, rows: 1, count: 1 },
  { id: '2x1', label: '2x1', cols: 2, rows: 1, count: 2 },
  { id: '1x2', label: '1x2', cols: 1, rows: 2, count: 2 },
  { id: '2x2', label: '2x2', cols: 2, rows: 2, count: 4 },
  { id: '3x2', label: '3x2', cols: 3, rows: 2, count: 6 },
];

/* ── Layout icon SVGs ──────────────────────────────────────────── */
function LayoutIcon({ cols, rows, active }) {
  const size = 24;
  const pad = 2;
  const gap = 1.5;
  const cellW = (size - pad * 2 - gap * (cols - 1)) / cols;
  const cellH = (size - pad * 2 - gap * (rows - 1)) / rows;
  const rects = [];
  for (let r = 0; r < rows; r++) {
    for (let c = 0; c < cols; c++) {
      rects.push(
        <rect
          key={`${r}-${c}`}
          x={pad + c * (cellW + gap)}
          y={pad + r * (cellH + gap)}
          width={cellW}
          height={cellH}
          rx={1.5}
          fill={active ? colors.blue : colors.textSecondary}
          opacity={active ? 1 : 0.5}
        />
      );
    }
  }
  return (
    <svg width={size} height={size} viewBox={`0 0 ${size} ${size}`}>
      {rects}
    </svg>
  );
}

/* ── Error boundary ────────────────────────────────────────────── */
class PaneErrorBoundary extends Component {
  constructor(props) {
    super(props);
    this.state = { hasError: false, error: null };
  }
  static getDerivedStateFromError(error) {
    return { hasError: true, error };
  }
  render() {
    if (this.state.hasError) {
      return (
        <div style={{
          display: 'flex', alignItems: 'center', justifyContent: 'center',
          height: '100%', color: colors.red, fontSize: '12px', textAlign: 'center',
          padding: '12px', fontFamily: mono,
        }}>
          Chart error: {this.state.error?.message || 'Unknown'}
        </div>
      );
    }
    return this.props.children;
  }
}

/* ── Bar time parser ───────────────────────────────────────────── */
function parseBarTime(bar, index) {
  const raw = bar.timestamp || bar.date || bar.time;
  if (raw != null) {
    if (typeof raw === 'number') return raw;
    const d = new Date(raw);
    if (!isNaN(d.getTime())) return Math.floor(d.getTime() / 1000);
  }
  return 1609459200 + index * 86400;
}

/* ── ChartPane ─────────────────────────────────────────────────── */
function ChartPane({ defaultSymbol, defaultTimeframe, onCrosshairMove, syncTime, paneId }) {
  const chartContainerRef = useRef(null);
  const chartRef = useRef(null);
  const candleSeriesRef = useRef(null);
  const volumeSeriesRef = useRef(null);
  const crosshairSubRef = useRef(null);

  const [symbol, setSymbol] = useState(defaultSymbol || 'SPY');
  const [inputValue, setInputValue] = useState(defaultSymbol || 'SPY');
  const [timeframe, setTimeframe] = useState(defaultTimeframe || '1D');
  const [bars, setBars] = useState([]);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState(null);

  /* Fetch OHLCV data */
  const fetchData = useCallback(async (sym, tf) => {
    if (!sym) return;
    setLoading(true);
    setError(null);
    try {
      const encoded = encodeURIComponent(sym);
      const data = await api(`/charts/ohlcv/${encoded}?timeframe=${encodeURIComponent(tf)}&bars=500`);
      if (data) {
        const rawBars = data.bars || data.data || [];
        const processed = rawBars.map((bar, i) => ({
          time: parseBarTime(bar, i),
          open: Number(bar.open),
          high: Number(bar.high),
          low: Number(bar.low),
          close: Number(bar.close),
          volume: Number(bar.volume) || 0,
        }));
        processed.sort((a, b) => a.time - b.time);
        const seen = new Set();
        const deduped = [];
        for (const bar of processed) {
          if (!seen.has(bar.time)) {
            seen.add(bar.time);
            deduped.push(bar);
          }
        }
        setBars(deduped);
      } else {
        setError('No data');
        setBars([]);
      }
    } catch (e) {
      setError(e.message || 'Fetch failed');
      setBars([]);
    }
    setLoading(false);
  }, []);

  /* Initial fetch */
  useEffect(() => {
    fetchData(symbol, timeframe);
  }, []);

  /* Symbol submit */
  const handleSymbolSubmit = (e) => {
    e.preventDefault();
    const sym = inputValue.trim().toUpperCase();
    if (sym && sym !== symbol) {
      setSymbol(sym);
      fetchData(sym, timeframe);
    }
  };

  /* Timeframe change */
  const handleTfChange = (tf) => {
    setTimeframe(tf);
    fetchData(symbol, tf);
  };

  /* Create/destroy chart */
  useEffect(() => {
    if (!chartContainerRef.current) return;

    const chart = createChart(chartContainerRef.current, {
      width: chartContainerRef.current.clientWidth,
      height: chartContainerRef.current.clientHeight,
      layout: {
        background: { type: ColorType.Solid, color: colors.surface },
        textColor: colors.textPrimary,
        fontFamily: mono,
        fontSize: 10,
      },
      grid: {
        vertLines: { color: colors.grid },
        horzLines: { color: colors.grid },
      },
      crosshair: {
        mode: CrosshairMode.Normal,
        vertLine: { color: colors.crosshair, width: 1, style: 2, labelBackgroundColor: colors.surface },
        horzLine: { color: colors.crosshair, width: 1, style: 2, labelBackgroundColor: colors.surface },
      },
      rightPriceScale: {
        borderColor: colors.border,
        scaleMargins: { top: 0.1, bottom: 0.25 },
      },
      timeScale: {
        borderColor: colors.border,
        timeVisible: true,
        secondsVisible: false,
      },
      handleScroll: { vertTouchDrag: false },
      watermark: { visible: false },
    });

    const candleSeries = chart.addSeries(CandlestickSeries, {
      upColor: colors.green,
      downColor: colors.red,
      borderDownColor: colors.red,
      borderUpColor: colors.green,
      wickDownColor: colors.red,
      wickUpColor: colors.green,
    });

    const volumeSeries = chart.addSeries(HistogramSeries, {
      priceFormat: { type: 'volume' },
      priceScaleId: 'volume',
    });

    chart.priceScale('volume').applyOptions({
      scaleMargins: { top: 0.8, bottom: 0 },
    });

    chartRef.current = chart;
    candleSeriesRef.current = candleSeries;
    volumeSeriesRef.current = volumeSeries;

    /* Crosshair sync — emit moves from this pane */
    crosshairSubRef.current = chart.subscribeCrosshairMove((param) => {
      if (onCrosshairMove && param.time) {
        onCrosshairMove(paneId, param.time);
      }
    });

    /* Resize observer */
    const ro = new ResizeObserver((entries) => {
      for (const entry of entries) {
        const { width, height } = entry.contentRect;
        if (width > 0 && height > 0) {
          chart.applyOptions({ width, height });
        }
      }
    });
    ro.observe(chartContainerRef.current);

    return () => {
      ro.disconnect();
      if (crosshairSubRef.current) {
        crosshairSubRef.current = null;
      }
      chart.remove();
      chartRef.current = null;
      candleSeriesRef.current = null;
      volumeSeriesRef.current = null;
    };
  }, [paneId, onCrosshairMove]);

  /* Update data on the chart */
  useEffect(() => {
    if (!candleSeriesRef.current || bars.length === 0) return;

    const candleData = bars.map(({ time, open, high, low, close }) => ({ time, open, high, low, close }));
    const volumeData = bars.map((bar) => ({
      time: bar.time,
      value: bar.volume,
      color: bar.close >= bar.open ? colors.volumeUp : colors.volumeDown,
    }));

    candleSeriesRef.current.setData(candleData);
    volumeSeriesRef.current.setData(volumeData);
    chartRef.current?.timeScale().fitContent();
  }, [bars]);

  /* Crosshair sync — receive synced time from other panes */
  useEffect(() => {
    if (!chartRef.current || syncTime == null) return;
    chartRef.current.setCrosshairPosition(undefined, undefined, syncTime);
  }, [syncTime]);

  /* ── Pane styles ── */
  const S = {
    pane: {
      display: 'flex',
      flexDirection: 'column',
      background: colors.surface,
      border: `1px solid ${colors.border}`,
      borderRadius: '6px',
      overflow: 'hidden',
      minHeight: 0,
    },
    toolbar: {
      display: 'flex',
      alignItems: 'center',
      gap: '4px',
      padding: '4px 6px',
      background: colors.bg,
      borderBottom: `1px solid ${colors.border}`,
      flexShrink: 0,
      flexWrap: 'wrap',
      minHeight: '32px',
    },
    symbolInput: {
      background: colors.surface2,
      border: `1px solid ${colors.border}`,
      borderRadius: '6px',
      padding: '2px 6px',
      color: colors.textPrimary,
      fontFamily: mono,
      fontSize: '12px',
      fontWeight: 700,
      width: '68px',
      outline: 'none',
    },
    tfBtn: (active) => ({
      background: active ? colors.blue : 'transparent',
      color: active ? colors.bg : colors.textSecondary,
      border: 'none',
      borderRadius: '6px',
      padding: '2px 5px',
      fontFamily: mono,
      fontSize: '10px',
      fontWeight: 600,
      cursor: 'pointer',
      lineHeight: '16px',
    }),
    chartArea: {
      flex: 1,
      position: 'relative',
      minHeight: 0,
    },
    overlay: {
      position: 'absolute',
      inset: 0,
      display: 'flex',
      flexDirection: 'column',
      alignItems: 'center',
      justifyContent: 'center',
      zIndex: 5,
      background: 'rgba(11,15,20,0.85)',
    },
    spinner: {
      width: '24px',
      height: '24px',
      border: `2px solid ${colors.border}`,
      borderTop: `2px solid ${colors.blue}`,
      borderRadius: '50%',
      animation: 'mc-spin 0.8s linear infinite',
    },
  };

  return (
    <div style={S.pane}>
      {/* Pane toolbar */}
      <div style={S.toolbar}>
        <form onSubmit={handleSymbolSubmit} style={{ display: 'flex', gap: '3px', alignItems: 'center' }}>
          <input
            type="text"
            value={inputValue}
            onChange={(e) => setInputValue(e.target.value.toUpperCase())}
            onBlur={handleSymbolSubmit}
            style={S.symbolInput}
          />
        </form>
        <div style={{ width: '1px', height: '16px', background: colors.border, margin: '0 2px' }} />
        {TIMEFRAMES.map((tf) => (
          <button key={tf} onClick={() => handleTfChange(tf)} style={S.tfBtn(timeframe === tf)}>
            {tf}
          </button>
        ))}
      </div>

      {/* Chart area */}
      <div style={S.chartArea}>
        {loading && (
          <div style={S.overlay}>
            <div style={S.spinner} />
            <style>{`@keyframes mc-spin { to { transform: rotate(360deg); } }`}</style>
          </div>
        )}

        {!loading && error && (
          <div style={{ ...S.overlay, color: colors.red, fontSize: '12px' }}>
            {error}
          </div>
        )}

        <div ref={chartContainerRef} style={{ width: '100%', height: '100%' }} />
      </div>
    </div>
  );
}

/* ── MultiChartLayout (main export) ────────────────────────────── */
export default function MultiChartLayout() {
  const [layoutId, setLayoutId] = useState('2x2');
  const [syncSource, setSyncSource] = useState(null);
  const [syncTime, setSyncTime] = useState(null);

  const layout = LAYOUTS.find((l) => l.id === layoutId) || LAYOUTS[3];

  /* Crosshair sync handler */
  const handleCrosshairMove = useCallback((paneId, time) => {
    setSyncSource(paneId);
    setSyncTime(time);
  }, []);

  /* Styles */
  const S = {
    wrapper: {
      display: 'flex',
      flexDirection: 'column',
      width: '100%',
      height: '100%',
      minHeight: 0,
    },
    toolbar: {
      display: 'flex',
      alignItems: 'center',
      gap: '6px',
      padding: '6px 10px',
      background: colors.bg,
      borderBottom: `1px solid ${colors.border}`,
      height: '40px',
      flexShrink: 0,
      boxSizing: 'border-box',
    },
    toolbarLabel: {
      fontFamily: mono,
      fontSize: '11px',
      color: colors.textSecondary,
      textTransform: 'uppercase',
      letterSpacing: '0.5px',
      marginRight: '4px',
    },
    layoutBtn: (active) => ({
      display: 'flex',
      alignItems: 'center',
      justifyContent: 'center',
      width: '32px',
      height: '28px',
      background: active ? colors.surface2 : 'transparent',
      border: active ? `1.5px solid ${colors.blue}` : `1px solid ${colors.border}`,
      borderRadius: '6px',
      cursor: 'pointer',
      padding: 0,
      transition: 'border-color 0.15s ease',
    }),
    grid: {
      display: 'grid',
      gridTemplateColumns: `repeat(${layout.cols}, 1fr)`,
      gridTemplateRows: `repeat(${layout.rows}, 1fr)`,
      gap: '4px',
      flex: 1,
      padding: '4px',
      minHeight: 0,
      overflow: 'hidden',
    },
  };

  return (
    <div style={S.wrapper}>
      {/* Layout selector toolbar */}
      <div style={S.toolbar}>
        <span style={S.toolbarLabel}>Layout</span>
        {LAYOUTS.map((l) => (
          <button
            key={l.id}
            onClick={() => setLayoutId(l.id)}
            style={S.layoutBtn(layoutId === l.id)}
            title={l.label}
          >
            <LayoutIcon cols={l.cols} rows={l.rows} active={layoutId === l.id} />
          </button>
        ))}
      </div>

      {/* Chart grid */}
      <div style={S.grid}>
        {Array.from({ length: layout.count }, (_, i) => (
          <PaneErrorBoundary key={`${layoutId}-${i}`}>
            <ChartPane
              paneId={i}
              defaultSymbol={DEFAULT_SYMBOLS[i] || DEFAULT_SYMBOLS[i % DEFAULT_SYMBOLS.length]}
              defaultTimeframe="1D"
              onCrosshairMove={handleCrosshairMove}
              syncTime={syncSource !== i ? syncTime : null}
            />
          </PaneErrorBoundary>
        ))}
      </div>
    </div>
  );
}
