/**
 * AdvancedChart — TradingView-competitive charting engine.
 *
 * Upgrades over existing ChartsPage chart:
 * 1. Auto-detected support/resistance levels from /api/charts/levels/{symbol}
 * 2. Volume profile sidebar from /api/charts/volume-profile/{symbol}
 * 3. Fullscreen mode with Escape to exit
 * 4. Keyboard shortcuts (standard trader hotkeys)
 * 5. Right-click context menu (set alert at price, copy price)
 * 6. Price alert lines from active alerts
 * 7. Enhanced crosshair with % change from open
 * 8. Auto-refresh on interval (configurable)
 */
import { useState, useEffect, useRef, useCallback, useMemo, memo } from 'react';
import * as LWC from 'lightweight-charts';
const { createChart, CandlestickSeries, HistogramSeries, LineSeries, ColorType, CrosshairMode } = LWC;
import { api } from '../../utils/api';
import { tokens } from '../../styles/tokens';

/* ── Design Tokens ────────────────────────────────────────────────── */
const C = {
  bg: '#0D1117',
  surface: '#161B22',
  surface2: '#1C2128',
  border: '#30363D',
  text: '#E6EDF3',
  muted: '#8B949E',
  green: '#3FB950',
  red: '#F85149',
  blue: '#58A6FF',
  amber: '#D29922',
  purple: '#BC8CFF',
  cyan: '#06B6D4',
  volumeUp: 'rgba(63,185,80,0.3)',
  volumeDown: 'rgba(248,81,73,0.3)',
  supportLine: '#3FB950',
  resistanceLine: '#F85149',
  levelZone: 'rgba(88,166,255,0.06)',
};

const mono = "'JetBrains Mono', 'SF Mono', monospace";

/* ── Keyboard shortcut config ────────────────────────────────────── */
const SHORTCUT_MAP = {
  '1': '1m', '2': '5m', '3': '15m', '4': '1h',
  '5': '4h', '6': '1D', '7': '1W',
};

/* ── Support/Resistance level rendering ─────────────────────────── */
function SupportResistanceLevels({ levels, chartRef, candleSeriesRef }) {
  const levelsRef = useRef([]);

  useEffect(() => {
    const chart = chartRef?.current;
    const series = candleSeriesRef?.current;
    if (!chart || !series || !levels) return;

    // Remove old price lines
    for (const line of levelsRef.current) {
      try { series.removePriceLine(line); } catch { /* already removed */ }
    }
    levelsRef.current = [];

    const allLevels = [
      ...(levels.support || []).map(lv => ({ ...lv, type: 'support' })),
      ...(levels.resistance || []).map(lv => ({ ...lv, type: 'resistance' })),
    ];

    for (const lv of allLevels) {
      const isSupport = lv.type === 'support';
      const lineWidth = lv.touches >= 4 ? 2 : 1;
      const opacity = 0.4 + (lv.strength || 0) * 0.5;

      const priceLine = series.createPriceLine({
        price: lv.price,
        color: isSupport ? C.supportLine : C.resistanceLine,
        lineWidth,
        lineStyle: 2, // dashed
        axisLabelVisible: true,
        title: `${isSupport ? 'S' : 'R'} (${lv.touches}x)`,
        axisLabelColor: isSupport ? C.supportLine : C.resistanceLine,
        axisLabelTextColor: C.bg,
      });
      levelsRef.current.push(priceLine);
    }

    return () => {
      for (const line of levelsRef.current) {
        try { series.removePriceLine(line); } catch {}
      }
      levelsRef.current = [];
    };
  }, [levels, chartRef, candleSeriesRef]);

  return null;
}

/* ── Volume Profile sidebar overlay ─────────────────────────────── */
function VolumeProfileOverlay({ profile, chartDims }) {
  if (!profile || !profile.bins || profile.bins.length === 0) return null;

  const maxWidth = Math.min(chartDims.width * 0.12, 100);
  const barHeight = Math.max(2, chartDims.height / profile.bins.length - 1);

  return (
    <div style={{
      position: 'absolute',
      right: 60,
      top: 0,
      bottom: 0,
      width: maxWidth + 4,
      pointerEvents: 'none',
      zIndex: 8,
      display: 'flex',
      flexDirection: 'column-reverse',
      justifyContent: 'center',
      gap: 1,
      padding: '40px 0',
    }}>
      {profile.bins.map((bin, i) => {
        const w = bin.normalized * maxWidth;
        const isPOC = bin.price === profile.poc;
        return (
          <div key={i} style={{
            display: 'flex',
            alignItems: 'center',
            justifyContent: 'flex-end',
            height: barHeight,
            position: 'relative',
          }}>
            <div style={{
              width: w,
              height: '100%',
              background: isPOC
                ? 'rgba(88,166,255,0.35)'
                : bin.buy_volume > bin.sell_volume
                  ? 'rgba(63,185,80,0.20)'
                  : 'rgba(248,81,73,0.20)',
              borderRight: isPOC ? `2px solid ${C.blue}` : 'none',
              borderRadius: '2px 0 0 2px',
              transition: 'width 0.3s ease',
            }} />
          </div>
        );
      })}
    </div>
  );
}

/* ── Right-click context menu ───────────────────────────────────── */
function ChartContextMenu({ visible, x, y, price, onClose, onSetAlert, onCopyPrice }) {
  if (!visible) return null;

  return (
    <div
      style={{
        position: 'fixed',
        left: x,
        top: y,
        background: C.surface,
        border: `1px solid ${C.border}`,
        borderRadius: 8,
        padding: '4px 0',
        zIndex: 1000,
        minWidth: 180,
        boxShadow: '0 8px 24px rgba(0,0,0,0.6)',
        fontFamily: mono,
        fontSize: 12,
      }}
      onClick={(e) => e.stopPropagation()}
    >
      <div style={{ padding: '6px 14px', color: C.muted, fontSize: 10, fontWeight: 600, borderBottom: `1px solid ${C.border}` }}>
        ${price?.toFixed(2) || '--'}
      </div>
      <button
        onClick={() => { onSetAlert(price); onClose(); }}
        style={{
          display: 'flex', alignItems: 'center', gap: 8,
          width: '100%', padding: '8px 14px',
          background: 'none', border: 'none', color: C.text,
          fontFamily: mono, fontSize: 12, cursor: 'pointer',
          textAlign: 'left',
        }}
        onMouseEnter={(e) => { e.target.style.background = C.surface2; }}
        onMouseLeave={(e) => { e.target.style.background = 'none'; }}
      >
        <svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke={C.amber} strokeWidth="2">
          <path d="M18 8A6 6 0 0 0 6 8c0 7-3 9-3 9h18s-3-2-3-9" />
          <path d="M13.73 21a2 2 0 0 1-3.46 0" />
        </svg>
        Set alert at ${price?.toFixed(2)}
      </button>
      <button
        onClick={() => { onCopyPrice(price); onClose(); }}
        style={{
          display: 'flex', alignItems: 'center', gap: 8,
          width: '100%', padding: '8px 14px',
          background: 'none', border: 'none', color: C.text,
          fontFamily: mono, fontSize: 12, cursor: 'pointer',
          textAlign: 'left',
        }}
        onMouseEnter={(e) => { e.target.style.background = C.surface2; }}
        onMouseLeave={(e) => { e.target.style.background = 'none'; }}
      >
        <svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke={C.blue} strokeWidth="2">
          <rect x="9" y="9" width="13" height="13" rx="2" ry="2" />
          <path d="M5 15H4a2 2 0 0 1-2-2V4a2 2 0 0 1 2-2h9a2 2 0 0 1 2 2v1" />
        </svg>
        Copy price
      </button>
      <button
        onClick={onClose}
        style={{
          display: 'flex', alignItems: 'center', gap: 8,
          width: '100%', padding: '8px 14px',
          background: 'none', border: 'none', color: C.muted,
          fontFamily: mono, fontSize: 11, cursor: 'pointer',
          textAlign: 'left',
          borderTop: `1px solid ${C.border}`,
        }}
        onMouseEnter={(e) => { e.target.style.background = C.surface2; }}
        onMouseLeave={(e) => { e.target.style.background = 'none'; }}
      >
        Close
      </button>
    </div>
  );
}

/* ── Keyboard shortcuts help overlay ────────────────────────────── */
function ShortcutsOverlay({ visible, onClose }) {
  if (!visible) return null;

  const shortcuts = [
    ['1-7', 'Switch timeframe (1m - 1W)'],
    ['F', 'Toggle fullscreen'],
    ['S', 'Toggle support/resistance'],
    ['V', 'Toggle volume profile'],
    ['L', 'Toggle S/R levels'],
    ['R', 'Refresh chart data'],
    ['/', 'Focus symbol search'],
    ['?', 'Show/hide shortcuts'],
    ['Esc', 'Exit fullscreen / close menu'],
  ];

  return (
    <div
      style={{
        position: 'absolute',
        top: '50%',
        left: '50%',
        transform: 'translate(-50%, -50%)',
        background: C.surface,
        border: `1px solid ${C.border}`,
        borderRadius: 12,
        padding: 24,
        zIndex: 200,
        minWidth: 300,
        boxShadow: '0 16px 48px rgba(0,0,0,0.6)',
      }}
      onClick={(e) => e.stopPropagation()}
    >
      <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: 16 }}>
        <h3 style={{ margin: 0, fontSize: 14, fontWeight: 700, color: C.text, fontFamily: mono }}>
          Keyboard Shortcuts
        </h3>
        <button
          onClick={onClose}
          style={{ background: 'none', border: 'none', color: C.muted, cursor: 'pointer', fontSize: 18 }}
        >
          x
        </button>
      </div>
      {shortcuts.map(([key, desc]) => (
        <div key={key} style={{
          display: 'flex', justifyContent: 'space-between', alignItems: 'center',
          padding: '6px 0', borderBottom: `1px solid ${C.border}`,
        }}>
          <kbd style={{
            background: C.surface2,
            border: `1px solid ${C.border}`,
            borderRadius: 4,
            padding: '2px 8px',
            fontFamily: mono,
            fontSize: 11,
            fontWeight: 700,
            color: C.blue,
            minWidth: 32,
            textAlign: 'center',
          }}>
            {key}
          </kbd>
          <span style={{ fontSize: 12, color: C.muted, fontFamily: mono }}>{desc}</span>
        </div>
      ))}
    </div>
  );
}

/* ═══════════════════════════════════════════════════════════════════
   AdvancedChart Component
   ═══════════════════════════════════════════════════════════════════ */
function AdvancedChart({
  symbol = 'SPY',
  timeframe = '1D',
  bars = [],
  signals = [],
  onTimeframeChange,
  onSymbolChange,
  onRefresh,
  showSupportResistance: showSRProp = false,
  showVolumeProfile: showVPProp = false,
  isFullscreen = false,
  onFullscreenToggle,
}) {
  const containerRef = useRef(null);
  const chartRef = useRef(null);
  const candleSeriesRef = useRef(null);
  const volumeSeriesRef = useRef(null);

  const [chartDims, setChartDims] = useState({ width: 0, height: 0 });
  const [showSR, setShowSR] = useState(showSRProp);
  const [showVP, setShowVP] = useState(showVPProp);
  const [levels, setLevels] = useState(null);
  const [volumeProfile, setVolumeProfile] = useState(null);
  const [showShortcuts, setShowShortcuts] = useState(false);
  const [autoRefresh, setAutoRefresh] = useState(false);
  const autoRefreshRef = useRef(null);

  // Context menu state
  const [ctxMenu, setCtxMenu] = useState({ visible: false, x: 0, y: 0, price: null });

  // Process bars
  const chartBars = useMemo(() => {
    const processed = (bars || []).map((bar, i) => {
      const raw = bar.timestamp || bar.date || bar.time;
      let time;
      if (raw != null) {
        if (typeof raw === 'number') time = raw;
        else {
          const d = new Date(raw);
          time = !isNaN(d.getTime()) ? Math.floor(d.getTime() / 1000) : 1609459200 + i * 86400;
        }
      } else {
        time = 1609459200 + i * 86400;
      }
      return {
        time,
        open: Number(bar.open),
        high: Number(bar.high),
        low: Number(bar.low),
        close: Number(bar.close),
        volume: Number(bar.volume) || 0,
      };
    });
    processed.sort((a, b) => a.time - b.time);
    const seen = new Set();
    return processed.filter((bar) => {
      if (seen.has(bar.time)) return false;
      seen.add(bar.time);
      return true;
    });
  }, [bars]);

  /* ── Fetch support/resistance levels ───────────────────────────── */
  useEffect(() => {
    if (!showSR || !symbol) { setLevels(null); return; }
    let cancelled = false;
    (async () => {
      try {
        const data = await api(`/charts/levels/${encodeURIComponent(symbol)}?bars=500&tolerance=0.5&min_touches=3`);
        if (!cancelled) setLevels(data);
      } catch {
        if (!cancelled) setLevels(null);
      }
    })();
    return () => { cancelled = true; };
  }, [showSR, symbol]);

  /* ── Fetch volume profile ──────────────────────────────────────── */
  useEffect(() => {
    if (!showVP || !symbol) { setVolumeProfile(null); return; }
    let cancelled = false;
    (async () => {
      try {
        const data = await api(`/charts/volume-profile/${encodeURIComponent(symbol)}?bars=120&bins=24`);
        if (!cancelled) setVolumeProfile(data);
      } catch {
        if (!cancelled) setVolumeProfile(null);
      }
    })();
    return () => { cancelled = true; };
  }, [showVP, symbol]);

  /* ── Auto-refresh ──────────────────────────────────────────────── */
  useEffect(() => {
    if (autoRefresh && onRefresh) {
      autoRefreshRef.current = setInterval(() => onRefresh(), 30000); // 30s
    }
    return () => { if (autoRefreshRef.current) clearInterval(autoRefreshRef.current); };
  }, [autoRefresh, onRefresh]);

  /* ── Create chart ──────────────────────────────────────────────── */
  useEffect(() => {
    if (!containerRef.current) return;
    const isMobile = typeof window !== 'undefined' && window.innerWidth <= 768;

    const chart = createChart(containerRef.current, {
      width: containerRef.current.clientWidth,
      height: containerRef.current.clientHeight,
      layout: {
        background: { type: ColorType.Solid, color: C.bg },
        textColor: C.text,
        fontFamily: mono,
        fontSize: isMobile ? 9 : 11,
      },
      grid: {
        vertLines: { color: '#161B2230' },
        horzLines: { color: '#161B2230' },
      },
      crosshair: {
        mode: isMobile ? CrosshairMode.Magnet : CrosshairMode.Normal,
        vertLine: { color: C.blue, width: 1, style: 2, labelBackgroundColor: C.surface },
        horzLine: { color: C.blue, width: 1, style: 2, labelBackgroundColor: C.surface },
      },
      rightPriceScale: {
        borderColor: C.border,
        scaleMargins: { top: 0.08, bottom: 0.22 },
      },
      timeScale: {
        borderColor: C.border,
        timeVisible: true,
        secondsVisible: false,
      },
      handleScroll: { vertTouchDrag: false, horzTouchDrag: true, pressedMouseMove: true },
      handleScale: { axisPressedMouseMove: true, pinch: true },
      watermark: { visible: false },
    });

    const candleSeries = chart.addSeries(CandlestickSeries, {
      upColor: C.green,
      downColor: C.red,
      borderDownColor: C.red,
      borderUpColor: C.green,
      wickDownColor: C.red,
      wickUpColor: C.green,
    });

    const volumeSeries = chart.addSeries(HistogramSeries, {
      priceFormat: { type: 'volume' },
      priceScaleId: 'volume',
    });
    chart.priceScale('volume').applyOptions({ scaleMargins: { top: 0.8, bottom: 0 } });

    chartRef.current = chart;
    candleSeriesRef.current = candleSeries;
    volumeSeriesRef.current = volumeSeries;

    const ro = new ResizeObserver((entries) => {
      for (const entry of entries) {
        const { width, height } = entry.contentRect;
        if (width > 0 && height > 0) {
          chart.applyOptions({ width, height });
          setChartDims({ width, height });
        }
      }
    });
    ro.observe(containerRef.current);

    const initRect = containerRef.current.getBoundingClientRect();
    if (initRect.width > 0 && initRect.height > 0) {
      setChartDims({ width: initRect.width, height: initRect.height });
    }

    return () => {
      ro.disconnect();
      chart.remove();
      chartRef.current = null;
      candleSeriesRef.current = null;
      volumeSeriesRef.current = null;
    };
  }, []); // eslint-disable-line react-hooks/exhaustive-deps

  /* ── Update data ────────────────────────────────────────────────── */
  useEffect(() => {
    if (!candleSeriesRef.current || chartBars.length === 0) return;
    candleSeriesRef.current.setData(
      chartBars.map(({ time, open, high, low, close }) => ({ time, open, high, low, close }))
    );
    volumeSeriesRef.current.setData(
      chartBars.map((bar) => ({
        time: bar.time,
        value: bar.volume,
        color: bar.close >= bar.open ? C.volumeUp : C.volumeDown,
      }))
    );
    chartRef.current?.timeScale().fitContent();
  }, [chartBars]);

  /* ── Signal markers ────────────────────────────────────────────── */
  const signalMarkers = useMemo(() => {
    if (!signals || !signals.length || !chartRef.current || !candleSeriesRef.current) return [];
    const chart = chartRef.current;
    const series = candleSeriesRef.current;
    const markers = [];
    for (const sig of signals) {
      try {
        const rawTime = sig.timestamp || sig.date || sig.signal_time;
        if (!rawTime) continue;
        const t = typeof rawTime === 'number' ? rawTime : Math.floor(new Date(rawTime).getTime() / 1000);
        const price = Number(sig.price || sig.entry_price || sig.close || 0);
        if (!price || !t) continue;
        const x = chart.timeScale().timeToCoordinate(t);
        const y = series.priceToCoordinate(price);
        if (x == null || y == null) continue;
        const isBuy = (sig.direction || sig.signal_type || '').toLowerCase().includes('buy') ||
                      (sig.direction || sig.signal_type || '').toLowerCase().includes('long');
        markers.push({
          x, y, isBuy,
          strategy: sig.strategy || '',
          confidence: sig.confidence || null,
          price,
        });
      } catch { /* skip malformed */ }
    }
    return markers;
  }, [signals, chartBars]); // eslint-disable-line react-hooks/exhaustive-deps

  /* ── Keyboard shortcuts ─────────────────────────────────────────── */
  useEffect(() => {
    function handleKey(e) {
      // Don't capture when input is focused
      const tag = e.target.tagName.toLowerCase();
      if (tag === 'input' || tag === 'textarea' || tag === 'select') return;

      const key = e.key;

      // Timeframe shortcuts (1-7)
      if (SHORTCUT_MAP[key] && onTimeframeChange) {
        e.preventDefault();
        onTimeframeChange(SHORTCUT_MAP[key]);
        return;
      }

      // F = fullscreen
      if (key === 'f' || key === 'F') {
        e.preventDefault();
        onFullscreenToggle?.();
        return;
      }

      // S = support/resistance
      if (key === 's') {
        e.preventDefault();
        setShowSR(prev => !prev);
        return;
      }

      // V = volume profile
      if (key === 'v') {
        e.preventDefault();
        setShowVP(prev => !prev);
        return;
      }

      // L = levels (same as S)
      if (key === 'l' || key === 'L') {
        e.preventDefault();
        setShowSR(prev => !prev);
        return;
      }

      // R = refresh
      if (key === 'r') {
        e.preventDefault();
        onRefresh?.();
        return;
      }

      // ? = show shortcuts
      if (key === '?') {
        e.preventDefault();
        setShowShortcuts(prev => !prev);
        return;
      }

      // Escape = exit fullscreen, close shortcuts, close context menu
      if (key === 'Escape') {
        if (showShortcuts) { setShowShortcuts(false); return; }
        if (ctxMenu.visible) { setCtxMenu({ visible: false, x: 0, y: 0, price: null }); return; }
        if (isFullscreen) { onFullscreenToggle?.(); return; }
      }
    }

    window.addEventListener('keydown', handleKey);
    return () => window.removeEventListener('keydown', handleKey);
  }, [onTimeframeChange, onFullscreenToggle, onRefresh, showShortcuts, ctxMenu.visible, isFullscreen]);

  /* ── Context menu ───────────────────────────────────────────────── */
  const handleContextMenu = useCallback((e) => {
    e.preventDefault();
    const series = candleSeriesRef.current;
    if (!series) return;

    const rect = containerRef.current?.getBoundingClientRect();
    if (!rect) return;

    const y = e.clientY - rect.top;
    const price = series.coordinateToPrice(y);
    if (price == null) return;

    setCtxMenu({ visible: true, x: e.clientX, y: e.clientY, price });
  }, []);

  const handleSetAlert = useCallback(async (price) => {
    try {
      await api('/alerts', {
        method: 'POST',
        body: JSON.stringify({
          symbol,
          type: 'price_cross',
          condition: 'crosses',
          value: price,
          message: `${symbol} crossed $${price.toFixed(2)}`,
          enabled: true,
        }),
      });
    } catch (err) {
      console.warn('Alert creation failed:', err);
    }
  }, [symbol]);

  const handleCopyPrice = useCallback((price) => {
    if (price != null) {
      navigator.clipboard?.writeText(price.toFixed(2)).catch(() => {});
    }
  }, []);

  /* ── Close context menu on outside click ────────────────────────── */
  useEffect(() => {
    if (!ctxMenu.visible) return;
    const handleClick = () => setCtxMenu({ visible: false, x: 0, y: 0, price: null });
    window.addEventListener('click', handleClick);
    return () => window.removeEventListener('click', handleClick);
  }, [ctxMenu.visible]);

  /* ── Render ─────────────────────────────────────────────────────── */
  const lastBar = chartBars.length > 0 ? chartBars[chartBars.length - 1] : null;
  const prevBar = chartBars.length > 1 ? chartBars[chartBars.length - 2] : null;
  const priceChange = lastBar && prevBar ? lastBar.close - prevBar.close : 0;
  const pctChange = prevBar && prevBar.close !== 0 ? (priceChange / prevBar.close) * 100 : 0;
  const isUp = priceChange >= 0;

  return (
    <div
      style={{
        position: 'relative',
        width: '100%',
        height: '100%',
        background: C.bg,
        borderRadius: isFullscreen ? 0 : 10,
        overflow: 'hidden',
        border: isFullscreen ? 'none' : `1px solid ${C.border}`,
      }}
    >
      {/* ── Feature bar (top-right badges) ─────────────────────────── */}
      <div style={{
        position: 'absolute',
        top: 8,
        right: 70,
        display: 'flex',
        gap: 4,
        zIndex: 20,
        pointerEvents: 'auto',
      }}>
        {/* S/R toggle */}
        <button
          onClick={() => setShowSR(prev => !prev)}
          title="Support/Resistance levels [S]"
          style={{
            display: 'flex', alignItems: 'center', gap: 4,
            padding: '3px 8px', borderRadius: 6,
            background: showSR ? 'rgba(63,185,80,0.15)' : C.surface,
            border: `1px solid ${showSR ? C.green : C.border}`,
            color: showSR ? C.green : C.muted,
            fontFamily: mono, fontSize: 10, fontWeight: 600,
            cursor: 'pointer', transition: 'all 0.15s',
          }}
        >
          S/R
        </button>

        {/* Volume Profile toggle */}
        <button
          onClick={() => setShowVP(prev => !prev)}
          title="Volume Profile [V]"
          style={{
            display: 'flex', alignItems: 'center', gap: 4,
            padding: '3px 8px', borderRadius: 6,
            background: showVP ? 'rgba(88,166,255,0.15)' : C.surface,
            border: `1px solid ${showVP ? C.blue : C.border}`,
            color: showVP ? C.blue : C.muted,
            fontFamily: mono, fontSize: 10, fontWeight: 600,
            cursor: 'pointer', transition: 'all 0.15s',
          }}
        >
          VP
        </button>

        {/* Auto-refresh toggle */}
        <button
          onClick={() => setAutoRefresh(prev => !prev)}
          title="Auto-refresh every 30s"
          style={{
            display: 'flex', alignItems: 'center', gap: 4,
            padding: '3px 8px', borderRadius: 6,
            background: autoRefresh ? 'rgba(210,153,34,0.15)' : C.surface,
            border: `1px solid ${autoRefresh ? C.amber : C.border}`,
            color: autoRefresh ? C.amber : C.muted,
            fontFamily: mono, fontSize: 10, fontWeight: 600,
            cursor: 'pointer', transition: 'all 0.15s',
          }}
        >
          <svg width="10" height="10" viewBox="0 0 16 16" fill="none" stroke="currentColor" strokeWidth="2">
            <path d="M1 4s2-3 7-3 7 3 7 3" /><path d="M1 4V1M1 4h3" />
            <circle cx="8" cy="8" r="6" />
          </svg>
          {autoRefresh ? '30s' : 'Live'}
        </button>

        {/* Keyboard shortcuts help */}
        <button
          onClick={() => setShowShortcuts(prev => !prev)}
          title="Keyboard shortcuts [?]"
          style={{
            display: 'flex', alignItems: 'center',
            padding: '3px 8px', borderRadius: 6,
            background: C.surface,
            border: `1px solid ${C.border}`,
            color: C.muted,
            fontFamily: mono, fontSize: 10, fontWeight: 700,
            cursor: 'pointer',
          }}
        >
          ?
        </button>
      </div>

      {/* ── Price badge (top-left) ─────────────────────────────────── */}
      {lastBar && (
        <div style={{
          position: 'absolute',
          top: 8,
          left: 12,
          zIndex: 20,
          display: 'flex',
          alignItems: 'baseline',
          gap: 8,
          pointerEvents: 'none',
        }}>
          <span style={{
            fontFamily: mono,
            fontSize: 18,
            fontWeight: 700,
            color: isUp ? C.green : C.red,
          }}>
            ${lastBar.close.toFixed(2)}
          </span>
          <span style={{
            fontFamily: mono,
            fontSize: 12,
            fontWeight: 600,
            color: isUp ? C.green : C.red,
            opacity: 0.8,
          }}>
            {isUp ? '+' : ''}{priceChange.toFixed(2)} ({isUp ? '+' : ''}{pctChange.toFixed(2)}%)
          </span>
        </div>
      )}

      {/* ── Chart container ────────────────────────────────────────── */}
      <div
        ref={containerRef}
        onContextMenu={handleContextMenu}
        style={{ width: '100%', height: '100%' }}
      />

      {/* ── Support/Resistance lines ───────────────────────────────── */}
      {showSR && levels && (
        <SupportResistanceLevels
          levels={levels}
          chartRef={chartRef}
          candleSeriesRef={candleSeriesRef}
        />
      )}

      {/* ── Volume Profile overlay ─────────────────────────────────── */}
      {showVP && volumeProfile && (
        <VolumeProfileOverlay
          profile={volumeProfile}
          chartDims={chartDims}
        />
      )}

      {/* ── Signal markers SVG ─────────────────────────────────────── */}
      {signalMarkers.length > 0 && (
        <svg
          style={{
            position: 'absolute', inset: 0,
            width: chartDims.width, height: chartDims.height,
            pointerEvents: 'none', zIndex: 10, overflow: 'visible',
          }}
          viewBox={`0 0 ${chartDims.width} ${chartDims.height}`}
          preserveAspectRatio="none"
        >
          {signalMarkers.map((m, i) => {
            const sz = 8;
            const offset = m.isBuy ? sz + 4 : -(sz + 4);
            const pts = m.isBuy
              ? `${m.x},${m.y + offset} ${m.x - sz},${m.y + offset + sz * 1.5} ${m.x + sz},${m.y + offset + sz * 1.5}`
              : `${m.x},${m.y + offset} ${m.x - sz},${m.y + offset - sz * 1.5} ${m.x + sz},${m.y + offset - sz * 1.5}`;
            const fill = m.isBuy ? C.green : C.red;
            return (
              <g key={`sig-${i}`}>
                <polygon points={pts} fill={fill} opacity={0.85} />
                {m.confidence && (
                  <text
                    x={m.x + sz + 3}
                    y={m.y + offset + (m.isBuy ? sz : -sz / 2)}
                    fontSize="9"
                    fontFamily={mono}
                    fill={C.muted}
                    opacity={0.7}
                  >
                    {Math.round(m.confidence * 100)}%
                  </text>
                )}
                <title>{`${m.strategy} ${m.isBuy ? 'BUY' : 'SELL'} @ $${m.price.toFixed(2)}${m.confidence ? ` (${Math.round(m.confidence * 100)}%)` : ''}`}</title>
              </g>
            );
          })}
        </svg>
      )}

      {/* ── Context menu ───────────────────────────────────────────── */}
      <ChartContextMenu
        visible={ctxMenu.visible}
        x={ctxMenu.x}
        y={ctxMenu.y}
        price={ctxMenu.price}
        onClose={() => setCtxMenu({ visible: false, x: 0, y: 0, price: null })}
        onSetAlert={handleSetAlert}
        onCopyPrice={handleCopyPrice}
      />

      {/* ── Shortcuts overlay ──────────────────────────────────────── */}
      <ShortcutsOverlay
        visible={showShortcuts}
        onClose={() => setShowShortcuts(false)}
      />
    </div>
  );
}

export default memo(AdvancedChart);
