/* ═══════════════════════════════════════════════════════════════════════════
   Indicator Computation Functions
   ═══════════════════════════════════════════════════════════════════════════ */
function computeSMA(bars, period) {
  const result = [];
  for (let i = 0; i < bars.length; i++) {
    if (i < period - 1) { result.push({ time: bars[i].time }); continue; }
    let sum = 0;
    for (let j = i - period + 1; j <= i; j++) sum += bars[j].close;
    result.push({ time: bars[i].time, value: sum / period });
  }
  return result.filter((d) => d.value !== undefined);
}

function computeEMA(bars, period) {
  const result = [];
  const k = 2 / (period + 1);
  let ema = null;
  for (let i = 0; i < bars.length; i++) {
    if (ema === null) {
      if (i < period - 1) { result.push({ time: bars[i].time }); continue; }
      let sum = 0;
      for (let j = i - period + 1; j <= i; j++) sum += bars[j].close;
      ema = sum / period;
    } else {
      ema = bars[i].close * k + ema * (1 - k);
    }
    result.push({ time: bars[i].time, value: ema });
  }
  return result.filter((d) => d.value !== undefined);
}

function computeRSI(bars, period = 14) {
  const result = [];
  if (bars.length < period + 1) return result;
  let avgGain = 0, avgLoss = 0;
  for (let i = 1; i <= period; i++) {
    const change = bars[i].close - bars[i - 1].close;
    if (change > 0) avgGain += change; else avgLoss += Math.abs(change);
  }
  avgGain /= period; avgLoss /= period;
  const rs0 = avgLoss === 0 ? 100 : avgGain / avgLoss;
  result.push({ time: bars[period].time, value: 100 - 100 / (1 + rs0) });
  for (let i = period + 1; i < bars.length; i++) {
    const change = bars[i].close - bars[i - 1].close;
    const gain = change > 0 ? change : 0;
    const loss = change < 0 ? Math.abs(change) : 0;
    avgGain = (avgGain * (period - 1) + gain) / period;
    avgLoss = (avgLoss * (period - 1) + loss) / period;
    const rs = avgLoss === 0 ? 100 : avgGain / avgLoss;
    result.push({ time: bars[i].time, value: 100 - 100 / (1 + rs) });
  }
  return result;
}

function computeMACD(bars, fast = 12, slow = 26, signal = 9) {
  const emaFast = computeEMA(bars, fast);
  const emaSlow = computeEMA(bars, slow);
  const slowMap = new Map(emaSlow.map(d => [d.time, d.value]));
  const macdLine = emaFast
    .filter(d => slowMap.has(d.time))
    .map(d => ({ time: d.time, close: d.value - slowMap.get(d.time) }));
  return macdLine.map(d => ({ time: d.time, value: d.close }));
}

function computeBollinger(bars, period = 20, stdDev = 2) {
  const upper = [], lower = [], middle = [];
  for (let i = 0; i < bars.length; i++) {
    if (i < period - 1) continue;
    let sum = 0;
    for (let j = i - period + 1; j <= i; j++) sum += bars[j].close;
    const mean = sum / period;
    let sqSum = 0;
    for (let j = i - period + 1; j <= i; j++) sqSum += (bars[j].close - mean) ** 2;
    const sd = Math.sqrt(sqSum / period);
    middle.push({ time: bars[i].time, value: mean });
    upper.push({ time: bars[i].time, value: mean + stdDev * sd });
    lower.push({ time: bars[i].time, value: mean - stdDev * sd });
  }
  return { upper, lower, middle };
}

function computeVWAP(bars) {
  const result = [];
  let cumulativePV = 0, cumulativeVol = 0;
  for (let i = 0; i < bars.length; i++) {
    const { time, high, low, close, volume } = bars[i];
    if (typeof high !== 'number' || typeof low !== 'number' || typeof close !== 'number' || !volume) {
      result.push({ time, value: undefined }); continue;
    }
    const typical = (high + low + close) / 3;
    cumulativePV += typical * volume;
    cumulativeVol += volume;
    result.push({ time, value: cumulativeVol > 0 ? cumulativePV / cumulativeVol : undefined });
  }
  return result.filter((d) => d.value !== undefined);
}

function computeVolumeProfile(bars, numBins = 24) {
  if (bars.length === 0) return [];
  let minP = Infinity, maxP = -Infinity;
  for (const b of bars) {
    if (b.low < minP) minP = b.low;
    if (b.high > maxP) maxP = b.high;
  }
  const range = maxP - minP;
  if (range === 0) return [];
  const binSize = range / numBins;
  const bins = Array.from({ length: numBins }, (_, i) => ({
    price: minP + binSize * (i + 0.5),
    volume: 0,
  }));
  for (const b of bars) {
    const midPrice = (b.high + b.low) / 2;
    const binIdx = Math.min(Math.floor((midPrice - minP) / binSize), numBins - 1);
    if (binIdx >= 0) bins[binIdx].volume += b.volume;
  }
  return bins;
}

function parseBarTime(bar, index) {
  const raw = bar.timestamp || bar.date || bar.time;
  if (raw != null) {
    if (typeof raw === 'number') return raw;
    const d = new Date(raw);
    if (!isNaN(d.getTime())) return Math.floor(d.getTime() / 1000);
  }
  return 1609459200 + index * 86400;
}

/* ═══════════════════════════════════════════════════════════════════════════
   localStorage Drawing Persistence
   ═══════════════════════════════════════════════════════════════════════════ */
function loadDrawings(symbol) {
  try {
    return JSON.parse(localStorage.getItem(DRAWING_STORAGE_KEY + symbol) || '[]');
  } catch { return []; }
}

function saveDrawings(symbol, drawings) {
  try {
    localStorage.setItem(DRAWING_STORAGE_KEY + symbol, JSON.stringify(drawings));
  } catch { /* localStorage full */ }
}

/* ═══════════════════════════════════════════════════════════════════════════
   Error Boundary
   ═══════════════════════════════════════════════════════════════════════════ */
class ChartErrorBoundary extends Component {
  constructor(props) { super(props); this.state = { hasError: false, error: null }; }
  static getDerivedStateFromError(error) { return { hasError: true, error }; }
  render() {
    if (this.state.hasError) {
      return <div className={s.errorBoundary}>Chart render error: {this.state.error?.message || 'Unknown error'}</div>;
    }
    return this.props.children;
  }
}

