/* ═══════════════════════════════════════════════════════════════════════════
   Watchlist Sidebar (Feature 7) — Enhanced with price + change %
   ═══════════════════════════════════════════════════════════════════════════ */
function WatchlistSidebar({ watchlists, symbol, onSelect, onClose, onAdd }) {
  const [prices, setPrices] = useState({});

  useEffect(() => {
    let cancelled = false;
    async function fetchPrices() {
      const allSymbols = new Set();
      for (const wl of watchlists) {
        for (const sym of wl.symbols || []) {
          allSymbols.add(typeof sym === 'string' ? sym : sym.symbol);
        }
      }
      const priceMap = {};
      // Fetch prices for watchlist symbols in parallel (batch of 6)
      const syms = Array.from(allSymbols);
      for (let i = 0; i < syms.length; i += 6) {
        const batch = syms.slice(i, i + 6);
        const results = await Promise.allSettled(
          batch.map(async (sym) => {
            const data = await api(`/charts/ohlcv/${encodeURIComponent(sym)}?timeframe=1D&bars=2`);
            const bars = data?.bars || data?.data || [];
            if (bars.length >= 1) {
              const last = bars[bars.length - 1];
              const prev = bars.length >= 2 ? bars[bars.length - 2] : last;
              const price = Number(last.close) || 0;
              const prevClose = Number(prev.close) || price;
              const change = prevClose ? ((price - prevClose) / prevClose) * 100 : 0;
              return { symbol: sym, price, change };
            }
            return { symbol: sym, price: 0, change: 0 };
          })
        );
        for (const r of results) {
          if (r.status === 'fulfilled' && r.value) {
            priceMap[r.value.symbol] = r.value;
          }
        }
      }
      if (!cancelled) setPrices(priceMap);
    }
    if (watchlists.length > 0) fetchPrices();
    return () => { cancelled = true; };
  }, [watchlists]);

  return (
    <div className={s.watchlistSidebar}>
      <div className={s.watchlistHeader}>
        <span className={s.watchlistTitle}>Watchlist</span>
        <button className={s.watchlistClose} onClick={onClose} aria-label="Close watchlist">
          <svg width="12" height="12" viewBox="0 0 12 12" fill="none" stroke="currentColor" strokeWidth="1.5" strokeLinecap="round">
            <path d="M1 1l10 10M11 1L1 11" />
          </svg>
        </button>
      </div>
      <div className={s.watchlistBody}>
        {watchlists.length === 0 && (
          <div className={s.watchlistEmpty}>No watchlists yet</div>
        )}
        {watchlists.map((wl) => (
          <div key={wl.id} className={s.watchlistGroup}>
            <div className={s.watchlistGroupName}>{wl.name}</div>
            {(wl.symbols || []).map((sym) => {
              const symStr = typeof sym === 'string' ? sym : sym.symbol;
              const priceInfo = prices[symStr];
              return (
                <button
                  key={symStr}
                  className={symStr === symbol ? s.watchlistSymActive : s.watchlistSym}
                  onClick={() => onSelect(symStr)}
                >
                  <span className={s.watchlistSymTicker}>{symStr}</span>
                  {priceInfo && (
                    <span className={s.watchlistSymPriceWrap}>
                      <span className={s.watchlistSymPrice}>${priceInfo.price.toFixed(2)}</span>
                      <span
                        className={s.watchlistSymChange}
                        style={{ color: priceInfo.change >= 0 ? 'var(--color-green, #22C55E)' : 'var(--color-red, #EF4444)' }}
                      >
                        {priceInfo.change >= 0 ? '+' : ''}{priceInfo.change.toFixed(2)}%
                      </span>
                    </span>
                  )}
                </button>
              );
            })}
          </div>
        ))}
      </div>
      {watchlists.length > 0 && (
        <button
          className={s.watchlistAddBtn}
          onClick={() => onAdd(watchlists[0].id, symbol)}
          title={`Add ${symbol} to ${watchlists[0].name}`}
        >
          + Add {symbol}
        </button>
      )}
    </div>
  );
}

/* ═══════════════════════════════════════════════════════════════════════════
   TradingViewChart — Core chart with crosshair tooltip + comparison mode
   ═══════════════════════════════════════════════════════════════════════════ */
function TradingViewChart({
  bars, indicators, activeIndicators, signals,
  onCrosshairData, compareSymbol, compareBars,
}) {
  const chartContainerRef = useRef(null);
  const chartRef = useRef(null);
  const candleSeriesRef = useRef(null);
  const volumeSeriesRef = useRef(null);
  const overlaySeriesRef = useRef({});
  const compareSeriesRef = useRef(null);
  const [chartDims, setChartDims] = useState({ width: 0, height: 0 });

  const chartBars = useMemo(() => {
    const processed = (bars || []).map((bar, i) => ({
      time: parseBarTime(bar, i),
      open: Number(bar.open), high: Number(bar.high),
      low: Number(bar.low), close: Number(bar.close),
      volume: Number(bar.volume) || 0,
    }));
    processed.sort((a, b) => a.time - b.time);
    const seen = new Set();
    return processed.filter((bar) => {
      if (seen.has(bar.time)) return false;
      seen.add(bar.time);
      return true;
    });
  }, [bars]);

  // Comparison line data (Feature 9)
  const compBars = useMemo(() => {
    if (!compareBars || compareBars.length === 0) return [];
    const processed = compareBars.map((bar, i) => ({
      time: parseBarTime(bar, i),
      value: Number(bar.close),
    }));
    processed.sort((a, b) => a.time - b.time);
    const seen = new Set();
    return processed.filter((d) => {
      if (seen.has(d.time)) return false;
      seen.add(d.time);
      return true;
    });
  }, [compareBars]);

  // Create / destroy chart
  useEffect(() => {
    if (!chartContainerRef.current) return;
    const isMobileChart = typeof window !== 'undefined' && window.innerWidth <= 768;
    const chart = createChart(chartContainerRef.current, {
      width: chartContainerRef.current.clientWidth,
      height: chartContainerRef.current.clientHeight,
      layout: {
        background: { type: ColorType.Solid, color: '#0D1117' },
        textColor: colors.textPrimary,
        fontFamily: mono,
        fontSize: isMobileChart ? 9 : 11,
      },
      grid: {
        vertLines: { color: '#161B2240' },
        horzLines: { color: '#161B2240' },
      },
      crosshair: {
        mode: (typeof window !== 'undefined' && window.innerWidth <= 1024) ? CrosshairMode.Magnet : CrosshairMode.Normal,
        vertLine: { color: colors.crosshair, width: 1, style: 2, labelBackgroundColor: '#161B22' },
        horzLine: { color: colors.crosshair, width: 1, style: 2, labelBackgroundColor: '#161B22' },
      },
      rightPriceScale: {
        borderColor: colors.border,
        scaleMargins: { top: 0.1, bottom: 0.25 },
      },
      timeScale: { borderColor: colors.border, timeVisible: true, secondsVisible: false },
      handleScroll: { vertTouchDrag: false, horzTouchDrag: true, pressedMouseMove: true },
      handleScale: { axisPressedMouseMove: true, pinch: true },
      watermark: { visible: false },
    });

    const candleSeries = chart.addSeries(CandlestickSeries, {
      upColor: colors.green, downColor: colors.red,
      borderDownColor: colors.red, borderUpColor: colors.green,
      wickDownColor: colors.red, wickUpColor: colors.green,
    });

    const volumeSeries = chart.addSeries(HistogramSeries, {
      priceFormat: { type: 'volume' },
      priceScaleId: 'volume',
    });
    chart.priceScale('volume').applyOptions({ scaleMargins: { top: 0.8, bottom: 0 } });

    // Subscribe to crosshair move for tooltip (Feature 8)
    chart.subscribeCrosshairMove((param) => {
      if (!param.time || !param.seriesData) {
        onCrosshairData?.(null);
        return;
      }
      const candleData = param.seriesData.get(candleSeries);
      if (candleData) {
        onCrosshairData?.({
          open: candleData.open,
          high: candleData.high,
          low: candleData.low,
          close: candleData.close,
          volume: param.seriesData.get(volumeSeries)?.value,
          time: param.time,
        });
      }
    });

    chartRef.current = chart;
    candleSeriesRef.current = candleSeries;
    volumeSeriesRef.current = volumeSeries;

    const resizeObserver = new ResizeObserver((entries) => {
      for (const entry of entries) {
        const { width, height } = entry.contentRect;
        if (width > 0 && height > 0) {
          chart.applyOptions({ width, height });
          setChartDims({ width, height });
        }
      }
    });
    resizeObserver.observe(chartContainerRef.current);
    const initRect = chartContainerRef.current.getBoundingClientRect();
    if (initRect.width > 0 && initRect.height > 0) setChartDims({ width: initRect.width, height: initRect.height });

    return () => {
      resizeObserver.disconnect();
      chart.remove();
      chartRef.current = null;
      candleSeriesRef.current = null;
      volumeSeriesRef.current = null;
      overlaySeriesRef.current = {};
      compareSeriesRef.current = null;
    };
  }, []); // eslint-disable-line react-hooks/exhaustive-deps

  // Update candle + volume data
  useEffect(() => {
    if (!candleSeriesRef.current || chartBars.length === 0) return;
    candleSeriesRef.current.setData(chartBars.map(({ time, open, high, low, close }) => ({ time, open, high, low, close })));
    volumeSeriesRef.current.setData(chartBars.map((bar) => ({
      time: bar.time, value: bar.volume,
      color: bar.close >= bar.open ? colors.volumeUp : colors.volumeDown,
    })));
    chartRef.current?.timeScale().fitContent();
  }, [chartBars]);

  // Comparison overlay (Feature 9)
  useEffect(() => {
    const chart = chartRef.current;
    if (!chart) return;
    if (compareSeriesRef.current) {
      chart.removeSeries(compareSeriesRef.current);
      compareSeriesRef.current = null;
    }
    if (compBars.length > 0 && compareSymbol) {
      const cSeries = chart.addSeries(LineSeries, {
        color: '#EC4899',
        lineWidth: 2,
        priceLineVisible: false,
        lastValueVisible: true,
        crosshairMarkerVisible: true,
        priceScaleId: 'compare',
        title: compareSymbol,
      });
      chart.priceScale('compare').applyOptions({
        scaleMargins: { top: 0.1, bottom: 0.25 },
        borderVisible: false,
      });
      cSeries.setData(compBars);
      compareSeriesRef.current = cSeries;
    }
  }, [compBars, compareSymbol]);

  // Update indicator overlays
  useEffect(() => {
    const chart = chartRef.current;
    if (!chart || chartBars.length === 0) return;

    for (const key of Object.keys(overlaySeriesRef.current)) {
      if (key.startsWith('BB 20_')) continue;
      if (!activeIndicators.includes(key)) {
        chart.removeSeries(overlaySeriesRef.current[key]);
        delete overlaySeriesRef.current[key];
      }
    }

    for (const ind of activeIndicators) {
      const smaMatch = ind.match(/^(SMA|EMA)\s+(\d+)$/);
      const lineColor = SMA_COLORS[ind] || colors.blue;

      if (smaMatch) {
        const [, type, periodStr] = smaMatch;
        const period = parseInt(periodStr, 10);
        const data = type === 'EMA' ? computeEMA(chartBars, period) : computeSMA(chartBars, period);
        if (!overlaySeriesRef.current[ind]) {
          const series = chart.addSeries(LineSeries, {
            color: lineColor, lineWidth: 1,
            priceLineVisible: false, lastValueVisible: false, crosshairMarkerVisible: false,
          });
          series.setData(data);
          overlaySeriesRef.current[ind] = series;
        } else {
          overlaySeriesRef.current[ind].setData(data);
        }
      } else if (ind === 'RSI 14') {
        const data = computeRSI(chartBars, 14);
        if (!overlaySeriesRef.current[ind]) {
          const series = chart.addSeries(LineSeries, {
            color: lineColor, lineWidth: 1.5,
            priceLineVisible: false, lastValueVisible: true,
            crosshairMarkerVisible: false, priceScaleId: 'rsi',
          });
          chart.priceScale('rsi').applyOptions({ scaleMargins: { top: 0.75, bottom: 0 }, borderVisible: false });
          series.setData(data);
          overlaySeriesRef.current[ind] = series;
        } else {
          overlaySeriesRef.current[ind].setData(data);
        }
      } else if (ind === 'MACD') {
        const data = computeMACD(chartBars, 12, 26, 9);
        if (!overlaySeriesRef.current[ind]) {
          const series = chart.addSeries(LineSeries, {
            color: lineColor, lineWidth: 1.5,
            priceLineVisible: false, lastValueVisible: true,
            crosshairMarkerVisible: false, priceScaleId: 'macd',
          });
          chart.priceScale('macd').applyOptions({ scaleMargins: { top: 0.8, bottom: 0 }, borderVisible: false });
          series.setData(data);
          overlaySeriesRef.current[ind] = series;
        } else {
          overlaySeriesRef.current[ind].setData(data);
        }
      } else if (ind === 'BB 20') {
        const { upper, lower, middle } = computeBollinger(chartBars, 20, 2);
        const bbKeys = ['BB 20_upper', 'BB 20_lower', 'BB 20_mid'];
        const bbData = [upper, lower, middle];
        for (let bi = 0; bi < 3; bi++) {
          const bk = bbKeys[bi];
          if (!overlaySeriesRef.current[bk]) {
            const series = chart.addSeries(LineSeries, {
              color: lineColor, lineWidth: 1,
              lineStyle: bi < 2 ? 2 : 0,
              priceLineVisible: false, lastValueVisible: false, crosshairMarkerVisible: false,
            });
            series.setData(bbData[bi]);
            overlaySeriesRef.current[bk] = series;
          } else {
            overlaySeriesRef.current[bk].setData(bbData[bi]);
          }
        }
      } else if (ind === 'VWAP') {
        const data = computeVWAP(chartBars);
        if (!overlaySeriesRef.current[ind]) {
          const series = chart.addSeries(LineSeries, {
            color: lineColor, lineWidth: 1.5, lineStyle: 1,
            priceLineVisible: false, lastValueVisible: true, crosshairMarkerVisible: false,
          });
          series.setData(data);
          overlaySeriesRef.current[ind] = series;
        } else {
          overlaySeriesRef.current[ind].setData(data);
        }
      }
    }

    if (!activeIndicators.includes('BB 20')) {
      for (const bk of ['BB 20_upper', 'BB 20_lower', 'BB 20_mid']) {
        if (overlaySeriesRef.current[bk]) {
          chart.removeSeries(overlaySeriesRef.current[bk]);
          delete overlaySeriesRef.current[bk];
        }
      }
    }
  }, [activeIndicators, chartBars]);

  // Server-side indicator overlays
  useEffect(() => {
    if (!chartRef.current || !indicators) return;
    const serverOverlays = indicators.sma || indicators.ema || {};
    for (const [key, values] of Object.entries(serverOverlays)) {
      if (!Array.isArray(values) || values.length === 0) continue;
      const label = `API_${key}`;
      if (overlaySeriesRef.current[label]) continue;
      const data = values
        .map((v, i) => ({ time: chartBars[i]?.time, value: Number(v) }))
        .filter((d) => d.time && !isNaN(d.value));
      if (data.length > 0) {
        const series = chartRef.current.addSeries(LineSeries, {
          color: colors.amber, lineWidth: 1, priceLineVisible: false, lastValueVisible: false,
        });
        series.setData(data);
        overlaySeriesRef.current[label] = series;
      }
    }
  }, [indicators, chartBars]);

  // Signal markers
  const signalMarkers = (() => {
    if (!signals || !signals.length || !chartRef.current || !candleSeriesRef.current) return [];
    const chart = chartRef.current;
    const series = candleSeriesRef.current;
    const markers = [];
    for (const sig of signals) {
      try {
        const rawTime = sig.timestamp || sig.date || sig.signal_time;
        if (!rawTime) continue;
        const t = typeof rawTime === 'number' ? rawTime : Math.floor(new Date(rawTime).getTime() / 1000);
        const price = Number(sig.price || sig.entry_price || sig.close || 0);
        if (!price || !t) continue;
        const x = chart.timeScale().timeToCoordinate(t);
        const y = series.priceToCoordinate(price);
        if (x == null || y == null) continue;
        const isBuy = (sig.direction || sig.signal_type || '').toLowerCase().includes('buy') ||
                      (sig.direction || sig.signal_type || '').toLowerCase().includes('long');
        markers.push({ x, y, isBuy, strategy: sig.strategy || '', price });
      } catch { /* skip malformed signal */ }
    }
    return markers;
  })();

  return (
    <div ref={chartContainerRef} className={s.chartInner} style={{ position: 'relative' }}>
      {signalMarkers.length > 0 && (
        <svg
          style={{
            position: 'absolute', inset: 0, width: chartDims.width, height: chartDims.height,
            pointerEvents: 'none', zIndex: 10, overflow: 'visible',
          }}
          viewBox={`0 0 ${chartDims.width} ${chartDims.height}`}
          preserveAspectRatio="none"
        >
          {signalMarkers.map((m, i) => {
            const sz = 8;
            const offset = m.isBuy ? sz + 4 : -(sz + 4);
            const pts = m.isBuy
              ? `${m.x},${m.y + offset} ${m.x - sz},${m.y + offset + sz * 1.5} ${m.x + sz},${m.y + offset + sz * 1.5}`
              : `${m.x},${m.y + offset} ${m.x - sz},${m.y + offset - sz * 1.5} ${m.x + sz},${m.y + offset - sz * 1.5}`;
            const fill = m.isBuy ? colors.green : colors.red;
            return (
              <g key={`sig-${i}`}>
                <polygon points={pts} fill={fill} opacity={0.85} />
                <title>{`${m.strategy} ${m.isBuy ? 'BUY' : 'SELL'} @ $${m.price.toFixed(2)}`}</title>
              </g>
            );
          })}
        </svg>
      )}
    </div>
  );
}

/* ═══════════════════════════════════════════════════════════════════════════
   Main ChartsPage Component
   ═══════════════════════════════════════════════════════════════════════════ */
export default function ChartsPage() {
  usePageTitle('Charts');
  useEffect(() => { handleBadgeProgress('charts_viewed', 1); }, []); // eslint-disable-line react-hooks/exhaustive-deps

  const { chartData, indicators, loading, error, fetchChart } = useChartData();
  const chartAreaRef = useRef(null);
  const { watchlists, addSymbol: addToWatchlist } = useWatchlists();

  // Core state
  const [symbol, setSymbol] = useState('AAPL');
  const [timeframe, setTimeframe] = useState('1D');
  const [activePeriod, setActivePeriod] = useState(null);
  const [activeIndicators, setActiveIndicators] = useState([]);

  const [indicatorState, setIndicatorState] = useState({
    sma: { enabled: false, period: 14 },
    ema: { enabled: false, period: 14 },
    rsi: { enabled: false, period: 14 },
    macd: { enabled: false, fastPeriod: 12, slowPeriod: 26, signalPeriod: 9 },
    bollinger: { enabled: false, period: 20, stdDev: 2 },
    vwap: { enabled: false },
    atr: { enabled: false, period: 14 },
  });

  const [indicatorPanelCollapsed, setIndicatorPanelCollapsed] = useState(false);
  const [mobileIndicatorPanelVisible, setMobileIndicatorPanelVisible] = useState(false);
  const [isMobile, setIsMobile] = useState(typeof window !== 'undefined' ? window.innerWidth < 768 : false);

  // Feature 4: Multi-chart layout state
  const [multiChartMode, setMultiChartMode] = useState(false);
  const [gridCount, setGridCount] = useState(1);

  // Feature 7: Watchlist sidebar
  const [watchlistOpen, setWatchlistOpen] = useState(false);

  // Feature 5: Signal overlay
  const [signals, setSignals] = useState([]);
  const [showSignals, setShowSignals] = useState(true);

  // Feature 1: Drawing tools state
  const [drawingTool, setDrawingTool] = useState(null);
  const [drawings, setDrawings] = useState([]);
  const [drawPending, setDrawPending] = useState([]);
  const [drawMouse, setDrawMouse] = useState(null);
  const [textInput, setTextInput] = useState('');
  const [textInputPos, setTextInputPos] = useState(null);
  const drawSvgRef = useRef(null);
  const [drawDims, setDrawDims] = useState({ width: 0, height: 0 });

  // Feature 8: Crosshair data
  const [crosshairData, setCrosshairData] = useState(null);

  // Feature 9: Comparison mode
  const [compareSymbol, setCompareSymbol] = useState('');
  const [compareInput, setCompareInput] = useState('');
  const [compareBars, setCompareBars] = useState([]);
  const [compareOpen, setCompareOpen] = useState(false);

  // Feature 6: Screenshot
  const [screenshotting, setScreenshotting] = useState(false);

  // Feature 10: Fullscreen chart mode
  const [isFullscreen, setIsFullscreen] = useState(false);

  // Feature 11: Support/Resistance levels
  const [showSR, setShowSR] = useState(false);

  // Feature 12: Volume Profile
  const [showVP, setShowVP] = useState(false);

  // Load saved drawings when symbol changes
  useEffect(() => {
    setDrawings(loadDrawings(symbol));
  }, [symbol]);

  // Save drawings when they change
  useEffect(() => {
    if (symbol) saveDrawings(symbol, drawings);
  }, [drawings, symbol]);

  // Track container dimensions for drawing SVG
  useEffect(() => {
    const el = chartAreaRef?.current;
    if (!el) return;
    const updateDims = () => {
      const rect = el.getBoundingClientRect();
      setDrawDims({ width: rect.width, height: rect.height });
    };
    updateDims();
    const obs = new ResizeObserver(updateDims);
    obs.observe(el);
    return () => obs.disconnect();
  }, []);

  // Fetch signals from multiple endpoints, merge and dedupe
  const fetchSignals = useCallback(async (sym) => {
    try {
      const allSignals = [];

      // Primary: GET /api/signals filtered by symbol
      const [signalsData, liveData] = await Promise.allSettled([
        api(`/signals?symbol=${encodeURIComponent(sym)}&days=30`, { silent: true }),
        api(`/scanners/signals/live`, { silent: true }),
      ]);

      // Collect from /api/signals
      if (signalsData.status === 'fulfilled' && signalsData.value) {
        const sigs = signalsData.value?.signals || signalsData.value?.results || signalsData.value || [];
        if (Array.isArray(sigs)) allSignals.push(...sigs);
      }

      // Collect from /api/scanners/signals/live, filter to current symbol
      if (liveData.status === 'fulfilled' && liveData.value) {
        const live = liveData.value?.signals || liveData.value?.results || liveData.value || [];
        if (Array.isArray(live)) {
          const filtered = live.filter(s => {
            const sigSym = (s.symbol || s.ticker || '').toUpperCase();
            return sigSym === sym.toUpperCase();
          });
          allSignals.push(...filtered);
        }
      }

      // Fallback: try legacy endpoints if primary returned nothing
      if (allSignals.length === 0) {
        try {
          const fallback = await api(`/track-record/signals?symbol=${encodeURIComponent(sym)}&days=30`, { silent: true });
          const fb = fallback?.signals || fallback?.results || fallback || [];
          if (Array.isArray(fb)) allSignals.push(...fb);
        } catch { /* ignore fallback failure */ }
      }

      // Dedupe by timestamp+direction
      const seen = new Set();
      const deduped = allSignals.filter(s => {
        const key = `${s.timestamp || s.date || s.signal_time}_${s.direction || s.signal_type}_${s.strategy || ''}`;
        if (seen.has(key)) return false;
        seen.add(key);
        return true;
      });

      setSignals(deduped);
    } catch { setSignals([]); }
  }, []);

  useEffect(() => { fetchChart(symbol, timeframe); fetchSignals(symbol); }, []); // eslint-disable-line react-hooks/exhaustive-deps

  // Responsive
  useEffect(() => {
    function handleResize() {
      const mobile = window.innerWidth < 768;
      setIsMobile(mobile);
      if (!mobile) { setMobileIndicatorPanelVisible(true); setIndicatorPanelCollapsed(false); }
      else { setMobileIndicatorPanelVisible(false); setIndicatorPanelCollapsed(true); }
    }
    handleResize();
    window.addEventListener('resize', handleResize);
    return () => window.removeEventListener('resize', handleResize);
  }, []);

  // Keyboard shortcuts for chart page
  useEffect(() => {
    function handleKeyDown(e) {
      const tag = e.target.tagName.toLowerCase();
      if (tag === 'input' || tag === 'textarea' || tag === 'select') return;
      if (multiChartMode) return; // shortcuts only in single-chart mode

      const SHORTCUT_TF = { '1': '1m', '2': '5m', '3': '15m', '4': '1h', '5': '4h', '6': '1D', '7': '1W' };
      if (SHORTCUT_TF[e.key]) {
        e.preventDefault();
        handleTimeframeChange(SHORTCUT_TF[e.key]);
        return;
      }
      if (e.key === 'f' || e.key === 'F') {
        e.preventDefault();
        setIsFullscreen(prev => !prev);
        return;
      }
      if (e.key === 's' && !e.ctrlKey && !e.metaKey) {
        e.preventDefault();
        setShowSR(prev => !prev);
        return;
      }
      if (e.key === 'v' && !e.ctrlKey && !e.metaKey) {
        e.preventDefault();
        setShowVP(prev => !prev);
        return;
      }
      if (e.key === 'r' && !e.ctrlKey && !e.metaKey) {
        e.preventDefault();
        fetchChart(symbol, timeframe);
        fetchSignals(symbol);
        return;
      }
      if (e.key === 'Escape') {
        if (isFullscreen) { setIsFullscreen(false); return; }
      }
    }
    window.addEventListener('keydown', handleKeyDown);
    return () => window.removeEventListener('keydown', handleKeyDown);
  }, [multiChartMode, symbol, timeframe, isFullscreen]); // eslint-disable-line react-hooks/exhaustive-deps

  // Handlers
  const handleSymbolSelect = useCallback((sym) => {
    const s = (sym || '').trim().toUpperCase();
    if (s) {
      setSymbol(s);
      setActivePeriod(null);
      fetchChart(s, timeframe);
      fetchSignals(s);
      setCompareSymbol(''); setCompareBars([]);
    }
  }, [timeframe, fetchChart, fetchSignals]);

  const handleTimeframeChange = (tf) => {
    setTimeframe(tf);
    setActivePeriod(null);
    fetchChart(symbol, tf);
  };

  const handlePeriodChange = useCallback((pill) => {
    setActivePeriod(pill.label);
    const tf = pill.days <= 7 ? '15m' : pill.days <= 30 ? '1h' : '1D';
    setTimeframe(tf);
    fetchChart(symbol, tf);
  }, [symbol, fetchChart]);

  const toggleIndicator = (ind) => {
    setActiveIndicators((prev) =>
      prev.includes(ind) ? prev.filter((i) => i !== ind) : [...prev, ind]
    );
  };

  // Feature 9: Compare symbol fetch
  const handleCompareSubmit = useCallback(async () => {
    const sym = compareInput.trim().toUpperCase();
    if (!sym || sym === symbol) return;
    setCompareSymbol(sym);
    setCompareOpen(false);
    try {
      const data = await api(`/charts/ohlcv/${encodeURIComponent(sym)}?timeframe=${encodeURIComponent(timeframe)}&bars=500`);
      setCompareBars(data?.bars || data?.data || []);
    } catch { setCompareBars([]); }
  }, [compareInput, symbol, timeframe]);

  const clearCompare = () => { setCompareSymbol(''); setCompareBars([]); setCompareInput(''); };

  // Feature 6: Screenshot
  const handleScreenshot = useCallback(() => {
    const chartEl = chartAreaRef.current;
    if (!chartEl) return;
    setScreenshotting(true);
    // Grab the canvas from the lightweight-charts container
    const canvas = chartEl.querySelector('canvas');
    if (canvas) {
      try {
        const dataUrl = canvas.toDataURL('image/png');
        const link = document.createElement('a');
        link.download = `${symbol}_${timeframe}_${new Date().toISOString().slice(0, 19).replace(/:/g, '-')}.png`;
        link.href = dataUrl;
        link.click();
      } catch (e) {
        console.warn('Screenshot failed:', e);
      }
    }
    setTimeout(() => setScreenshotting(false), 300);
  }, [symbol, timeframe]);

  // Drawing tool handlers
  const getRelativePos = useCallback((e) => {
    const el = chartAreaRef?.current;
    if (!el) return null;
    const rect = el.getBoundingClientRect();
    return { x: e.clientX - rect.left, y: e.clientY - rect.top };
  }, []);

  const handleDrawClick = useCallback((e) => {
    if (!drawingTool) return;
    const pos = getRelativePos(e);
    if (!pos) return;

    if (drawingTool === 'text') {
      setTextInputPos(pos);
      return;
    }

    const tool = DRAWING_TOOLS.find((t) => t.id === drawingTool);
    if (!tool) return;
    const newPoints = [...drawPending, pos];
    if (newPoints.length >= tool.points) {
      setDrawings((prev) => [...prev, {
        type: drawingTool, points: newPoints,
        color: drawingTool === 'fibonacci' ? '#F59E0B' : '#60A5FA',
      }]);
      setDrawPending([]);
      setDrawMouse(null);
    } else {
      setDrawPending(newPoints);
    }
  }, [drawingTool, drawPending, getRelativePos]);

  const handleDrawMouseMove = useCallback((e) => {
    if (!drawingTool || drawPending.length === 0) { setDrawMouse(null); return; }
    const pos = getRelativePos(e);
    if (pos) setDrawMouse(pos);
  }, [drawingTool, drawPending, getRelativePos]);

  const handleTextSubmit = useCallback(() => {
    if (textInputPos && textInput.trim()) {
      setDrawings((prev) => [...prev, {
        type: 'text', points: [textInputPos], text: textInput.trim(), color: '#E6EDF3',
      }]);
    }
    setTextInput('');
    setTextInputPos(null);
  }, [textInputPos, textInput]);

  const handleUndoDrawing = () => setDrawings((prev) => prev.slice(0, -1));
  const handleClearDrawings = () => { setDrawings([]); setDrawPending([]); setDrawMouse(null); };

  // Render a single drawing
  function renderDrawing(drawing, idx, isPreview = false) {
    const { type, points, color } = drawing;
    const opacity = isPreview ? 0.5 : 0.85;
    const key = isPreview ? `preview-${idx}` : `drawing-${idx}`;
    const w = drawDims.width;

    if (type === 'trendline' && points.length === 2) {
      return (
        <line key={key} x1={points[0].x} y1={points[0].y} x2={points[1].x} y2={points[1].y}
          stroke={color} strokeWidth={2} opacity={opacity} strokeLinecap="round" />
      );
    }
    if (type === 'hline' && points.length >= 1) {
      return (
        <line key={key} x1={0} y1={points[0].y} x2={w} y2={points[0].y}
          stroke={color} strokeWidth={1.5} strokeDasharray="6 3" opacity={opacity} />
      );
    }
    if (type === 'fibonacci' && points.length === 2) {
      const y1 = points[0].y, y2 = points[1].y, range = y2 - y1;
      return (
        <g key={key} opacity={opacity}>
          {FIB_LEVELS.map((level) => {
            const y = y1 + range * level;
            const pct = (level * 100).toFixed(1);
            return (
              <g key={`${key}-fib-${level}`}>
                <line x1={0} y1={y} x2={w} y2={y} stroke="#F59E0B" strokeWidth={1}
                  strokeDasharray={level === 0 || level === 1 ? 'none' : '4 2'} />
                <text x={8} y={y - 4} fontSize="10" fontFamily="'JetBrains Mono', monospace"
                  fill="#8B949E" style={{ pointerEvents: 'none', userSelect: 'none' }}>{pct}%</text>
              </g>
            );
          })}
          <rect x={0} y={y1 + range * 0.382} width={w} height={range * (0.618 - 0.382)}
            fill="#F59E0B" opacity={0.06} />
        </g>
      );
    }
    if (type === 'rectangle' && points.length === 2) {
      const x = Math.min(points[0].x, points[1].x), y = Math.min(points[0].y, points[1].y);
      const rw = Math.abs(points[1].x - points[0].x), rh = Math.abs(points[1].y - points[0].y);
      return (
        <rect key={key} x={x} y={y} width={rw} height={rh}
          fill={color} fillOpacity={isPreview ? 0.08 : 0.12}
          stroke={color} strokeWidth={1.5} opacity={opacity} rx={2} />
      );
    }
    if (type === 'text' && points.length >= 1 && drawing.text) {
      return (
        <text key={key} x={points[0].x} y={points[0].y} fontSize="13"
          fontFamily="'JetBrains Mono', monospace" fill={color} opacity={opacity}
          style={{ pointerEvents: 'none', userSelect: 'none' }}>
          {drawing.text}
        </text>
      );
    }
    return null;
  }

  const previewDrawing = drawingTool && drawPending.length > 0 && drawMouse
    ? { type: drawingTool, points: [...drawPending, drawMouse], color: drawingTool === 'fibonacci' ? '#F59E0B' : '#60A5FA' }
    : null;

  const bars = chartData?.bars || chartData?.data || [];
  const lastBar = bars.length > 0 ? bars[bars.length - 1] : null;
  const lastPrice = lastBar ? Number(lastBar.close) || 0 : null;

  return (
    <div className={s.page}>
      {/* Upsell for drawing tools / comparison */}
      <UpsellBanner preset="drawing_tools" />

      {/* ── Header Row ─────────────────────────────────────────────── */}
      <div className={s.headerRow}>
        <h1 className={s.title}>Charts</h1>
        <div className={s.symbolSearchWrap}>
          <SymbolSearch onSelect={handleSymbolSelect} placeholder="Search symbols..." compact showRecent />
        </div>
        <div className={s.spacer} />

        {/* Feature 6: Screenshot button */}
        <button
          onClick={handleScreenshot}
          className={s.actionBtn}
          disabled={screenshotting}
          title="Save chart as PNG"
        >
          <svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
            <rect x="3" y="3" width="18" height="18" rx="2" /><circle cx="8.5" cy="8.5" r="1.5" />
            <path d="M21 15l-5-5L5 21" />
          </svg>
          {!isMobile && <span>Screenshot</span>}
        </button>

        {/* Feature 9: Compare button */}
        <div style={{ position: 'relative' }}>
          {/* Comparison mode (Starter+ required) */}
          {tierMeetsMin('starter') ? (
            <>
              <button
                onClick={() => setCompareOpen((v) => !v)}
                className={compareSymbol ? s.actionBtnActive : s.actionBtn}
                title="Compare with another symbol"
              >
                <svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round">
                  <path d="M18 20V10M12 20V4M6 20v-6" />
                </svg>
                {!isMobile && <span>{compareSymbol || 'Compare'}</span>}
              </button>
              {compareOpen && (
                <div className={s.compareDropdown}>
                  <form onSubmit={(e) => { e.preventDefault(); handleCompareSubmit(); }} style={{ display: 'flex', gap: 6 }}>
                    <input
                      type="text"
                      value={compareInput}
                      onChange={(e) => setCompareInput(e.target.value.toUpperCase())}
                      placeholder="MSFT"
                      className={s.compareInput}
                      autoFocus
                    />
                    <button type="submit" className={s.compareSubmitBtn}>Go</button>
                  </form>
                  {compareSymbol && (
                    <button onClick={clearCompare} className={s.compareClearBtn}>Clear comparison</button>
                  )}
                </div>
              )}
            </>
          ) : (
            <button
              onClick={() => window.location.href = '/pricing-plans'}
              className={s.actionBtn}
              title="Comparison mode requires Starter+"
              style={{ opacity: 0.6 }}
            >
              <svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2">
                <rect x="3" y="11" width="18" height="11" rx="2" ry="2" /><path d="M7 11V7a5 5 0 0110 0v4" />
              </svg>
              {!isMobile && <span>Compare</span>}
            </button>
          )}
        </div>

        {/* Feature 5: Signal toggle */}
        <button
          onClick={() => setShowSignals((v) => !v)}
          className={showSignals ? s.actionBtnActive : s.actionBtn}
          title={`${showSignals ? 'Hide' : 'Show'} signal overlays`}
        >
          <svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2">
            <polygon points="12,2 22,20 2,20" />
          </svg>
          {!isMobile && <span>Signals{signals.length > 0 ? ` (${signals.length})` : ''}</span>}
        </button>

        {/* Quick Trade */}
        {!multiChartMode && (
          <QuickTradePanel symbol={symbol} lastPrice={lastPrice} isMobile={isMobile}
            onOrderPlaced={() => fetchChart(symbol, timeframe)} />
        )}

        {/* Feature 7: Watchlist toggle */}
        {!isMobile && (
          <button
            onClick={() => setWatchlistOpen((v) => !v)}
            className={watchlistOpen ? s.watchlistBtnActive : s.watchlistBtnInactive}
            title="Watchlist"
          >
            <svg width="14" height="14" viewBox="0 0 16 16" fill="none" stroke="currentColor" strokeWidth="1.3">
              <path d="M8 1.5l1.76 3.56 3.93.57-2.84 2.77.67 3.9L8 10.42l-3.52 1.88.67-3.9L2.31 5.63l3.93-.57z" />
            </svg>
            {!isMobile && 'Watchlist'}
          </button>
        )}

        {/* Feature 4: Multi-chart grid buttons */}
        <div className={s.gridBtnGroup}>
          {MULTI_CHART_LAYOUTS.map((layout) => (
            <button
              key={layout.id}
              onClick={() => {
                if (layout.id === 1) { setMultiChartMode(false); setGridCount(1); }
                else { setMultiChartMode(true); setGridCount(layout.id); }
              }}
              className={
                (!multiChartMode && layout.id === 1) || (multiChartMode && gridCount === layout.id)
                  ? s.gridBtnActive
                  : s.gridBtn
              }
              title={`${layout.label} chart${layout.id > 1 ? 's' : ''}`}
            >
              <svg width="16" height="16" viewBox="0 0 16 16" fill="none">
                {Array.from({ length: layout.rows }, (_, r) =>
                  Array.from({ length: layout.cols }, (_, c) => {
                    const gap = 1;
                    const cw = (14 - gap * (layout.cols - 1)) / layout.cols;
                    const ch = (14 - gap * (layout.rows - 1)) / layout.rows;
                    return (
                      <rect key={`${r}-${c}`}
                        x={1 + c * (cw + gap)} y={1 + r * (ch + gap)}
                        width={cw} height={ch} rx={1}
                        stroke="currentColor" strokeWidth="1.2" fill="none"
                      />
                    );
                  })
                )}
              </svg>
            </button>
          ))}
        </div>
      </div>

      {/* ── Multi-Chart Mode ──────────────────────────────────────── */}
      {multiChartMode && (
        <div className={s.multiChartContainer}>
          <MultiChartLayout />
        </div>
      )}

      {/* ── Fullscreen Overlay ──────────────────────────────────────── */}
      {isFullscreen && !multiChartMode && (
        <div className={s.fullscreenOverlay}>
          <ChartToolbar
            timeframe={timeframe}
            onTimeframeChange={handleTimeframeChange}
            activeIndicators={activeIndicators}
            onToggleIndicator={toggleIndicator}
            activeLayout={1}
            onLayoutChange={() => {}}
            isFullscreen={isFullscreen}
            onFullscreenToggle={() => setIsFullscreen(false)}
            showSR={showSR}
            onToggleSR={() => setShowSR(prev => !prev)}
            showVP={showVP}
            onToggleVP={() => setShowVP(prev => !prev)}
            showSignals={showSignals}
            onToggleSignals={() => setShowSignals(prev => !prev)}
            signalCount={signals.length}
            onScreenshot={handleScreenshot}
          />
          <div style={{ flex: 1, position: 'relative', minHeight: 0 }}>
            <AdvancedChart
              symbol={symbol}
              timeframe={timeframe}
              bars={bars}
              signals={showSignals ? signals : []}
              onTimeframeChange={handleTimeframeChange}
              onSymbolChange={handleSymbolSelect}
              onRefresh={() => { fetchChart(symbol, timeframe); fetchSignals(symbol); }}
              showSupportResistance={showSR}
              showVolumeProfile={showVP}
              isFullscreen={true}
              onFullscreenToggle={() => setIsFullscreen(false)}
            />
          </div>
        </div>
      )}

      {/* ── Single-Chart Mode ─────────────────────────────────────── */}
      {!multiChartMode && !isFullscreen && (
        <>
          {/* Unified Chart Toolbar */}
          <ChartToolbar
            timeframe={timeframe}
            onTimeframeChange={handleTimeframeChange}
            activeIndicators={activeIndicators}
            onToggleIndicator={toggleIndicator}
            activeLayout={gridCount}
            onLayoutChange={(count) => {
              if (count === 1) { setMultiChartMode(false); setGridCount(1); }
              else { setMultiChartMode(true); setGridCount(count); }
            }}
            isFullscreen={isFullscreen}
            onFullscreenToggle={() => setIsFullscreen(true)}
            showSR={showSR}
            onToggleSR={() => setShowSR(prev => !prev)}
            showVP={showVP}
            onToggleVP={() => setShowVP(prev => !prev)}
            showSignals={showSignals}
            onToggleSignals={() => setShowSignals(prev => !prev)}
            signalCount={signals.length}
            onScreenshot={handleScreenshot}
          />

          {/* Timeframe Row — Period pills + granularity (Feature 3) */}
          <div className={s.periodRow}>
            {PERIOD_PILLS.map((pill) => (
              <button key={pill.label}
                onClick={() => handlePeriodChange(pill)}
                className={activePeriod === pill.label ? s.periodBtnActive : s.periodBtnInactive}
              >
                {pill.label}
              </button>
            ))}
            <div className={s.periodDivider} />
            {TIMEFRAMES.map((tf) => (
              <button key={tf}
                onClick={() => handleTimeframeChange(tf)}
                className={timeframe === tf && !activePeriod ? s.tfBtnActive : s.tfBtnInactive}
              >
                {tf}
              </button>
            ))}
          </div>

          {/* Symbol display + inline OHLCV */}
          <div className={s.symbolRow}>
            <span className={s.symbolDisplay}>{symbol}</span>
            <span className={s.symbolTimeframe}>{timeframe}</span>
            {compareSymbol && (
              <span className={s.compareTag}>
                vs {compareSymbol}
                <button className={s.compareTagClose} onClick={clearCompare}>x</button>
              </span>
            )}
            {lastBar && (
              <div className={s.ohlcvInline}>
                <span style={{ color: colors.textPrimary }}>O <b>{(Number(lastBar.open) || 0).toFixed(2)}</b></span>
                <span style={{ color: colors.green }}>H <b>{(Number(lastBar.high) || 0).toFixed(2)}</b></span>
                <span style={{ color: colors.red }}>L <b>{(Number(lastBar.low) || 0).toFixed(2)}</b></span>
                <span style={{ color: (Number(lastBar.close) || 0) >= (Number(lastBar.open) || 0) ? colors.green : colors.red }}>
                  C <b>{(Number(lastBar.close) || 0).toFixed(2)}</b>
                </span>
                <span style={{ color: colors.blue }}>V <b>{Number(lastBar.volume).toLocaleString()}</b></span>
              </div>
            )}
          </div>

          {/* Main layout: watchlist + indicators + chart + crosshair tooltip */}
          <div className={s.mainLayout}>
            {/* Watchlist sidebar (Feature 7) */}
            {!isMobile && watchlistOpen && (
              <WatchlistSidebar
                watchlists={watchlists}
                symbol={symbol}
                onSelect={handleSymbolSelect}
                onClose={() => setWatchlistOpen(false)}
                onAdd={addToWatchlist}
              />
            )}

            {/* Chart + indicator container */}
            <div className={isMobile ? s.chartContainerMobile : s.chartContainerDesktop}>
              {isMobile && (
                <button
                  onClick={() => setMobileIndicatorPanelVisible((v) => !v)}
                  className={s.mobileIndicatorToggle}
                  aria-expanded={mobileIndicatorPanelVisible}
                >
                  Indicators &#x25BE;
                </button>
              )}

              {(mobileIndicatorPanelVisible || !isMobile) && (
                <div className={isMobile ? s.indicatorPanelWrapperMobile : s.indicatorPanelWrapper}>
                  <IndicatorPanel
                    activeIndicators={indicatorState}
                    onToggle={(key) => setIndicatorState(prev => ({
                      ...prev, [key]: { ...prev[key], enabled: !prev[key].enabled }
                    }))}
                    onParamChange={(key, param, value) => setIndicatorState(prev => ({
                      ...prev, [key]: { ...prev[key], [param]: value }
                    }))}
                    collapsed={indicatorPanelCollapsed}
                    onCollapse={() => setIndicatorPanelCollapsed(prev => !prev)}
                  />
                </div>
              )}

              {/* Chart area */}
              <div ref={chartAreaRef} className={isMobile ? s.chartAreaMobile : s.chartArea}>
                {/* Feature 1: Drawing Tools Panel (Starter+ required) */}
                <TierGate requiredTier="starter" feature="Drawing tools require Starter+" inline>
                  <DrawingToolsPanel
                    activeTool={drawingTool}
                    onToolSelect={setDrawingTool}
                    onClear={handleClearDrawings}
                    onUndo={handleUndoDrawing}
                  />
                </TierGate>

                {/* Feature 8: Crosshair OHLCV tooltip */}
                <CrosshairTooltip data={crosshairData} visible={!!crosshairData} />

                {/* Drawing SVG overlay */}
                <svg
                  ref={drawSvgRef}
                  className={s.drawingSvgOverlay}
                  style={{ pointerEvents: drawingTool ? 'auto' : 'none', cursor: drawingTool ? 'crosshair' : 'default' }}
                  viewBox={`0 0 ${drawDims.width} ${drawDims.height}`}
                  preserveAspectRatio="none"
                  onClick={handleDrawClick}
                  onMouseMove={handleDrawMouseMove}
                  onMouseLeave={() => setDrawMouse(null)}
                >
                  {drawings.filter((d) => d.type !== 'text' || d.text).map((d, i) => renderDrawing(d, i))}
                  {previewDrawing && renderDrawing(previewDrawing, 0, true)}
                  {drawPending.map((pt, i) => (
                    <circle key={`pending-${i}`} cx={pt.x} cy={pt.y} r={4}
                      fill="#60A5FA" stroke="#0D1117" strokeWidth={1.5} opacity={0.9} />
                  ))}
                </svg>

                {/* Text annotation input (Feature 1) */}
                {textInputPos && (
                  <div className={s.textAnnotationInput}
                    style={{ left: textInputPos.x, top: textInputPos.y }}>
                    <input
                      type="text"
                      value={textInput}
                      onChange={(e) => setTextInput(e.target.value)}
                      onKeyDown={(e) => { if (e.key === 'Enter') handleTextSubmit(); if (e.key === 'Escape') { setTextInputPos(null); setTextInput(''); } }}
                      placeholder="Type annotation..."
                      autoFocus
                      className={s.textAnnotationField}
                    />
                    <button onClick={handleTextSubmit} className={s.textAnnotationOk}>OK</button>
                  </div>
                )}

                {loading && (
                  <div className={s.loadingOverlay}>
                    <div className={s.loadingSpinner} />
                    <span className={s.loadingText}>Loading chart data...</span>
                  </div>
                )}

                {!loading && error && (
                  <div className={s.errorState}>
                    {typeof error === 'string' ? error : error?.message || 'An error occurred'}
                  </div>
                )}

                {!loading && !error && bars.length === 0 && (
                  <div className={s.emptyChart}>
                    <svg width="56" height="56" viewBox="0 0 24 24" fill="none" stroke={colors.textSecondary} strokeWidth="1.5">
                      <rect x="3" y="3" width="18" height="18" rx="2" /><path d="M3 9h18M9 3v18" />
                    </svg>
                    <span className={s.emptyChartText}>Select a symbol to view chart</span>
                  </div>
                )}

                {bars.length > 0 && (
                  <ChartErrorBoundary>
                    <TradingViewChart
                      key={`${symbol}-${timeframe}`}
                      bars={bars}
                      indicators={indicators}
                      activeIndicators={activeIndicators}
                      signals={showSignals ? signals : []}
                      onCrosshairData={setCrosshairData}
                      compareSymbol={compareSymbol}
                      compareBars={compareBars}
                    />
                  </ChartErrorBoundary>
                )}

                <img src="/images/logo-main.webp" alt="Aura" loading="lazy" className={s.logoWatermark} />
              </div>
            </div>
          </div>

          {/* ── Indicator Selector (Feature 2) — Overlay toggles ──── */}
          <div className={s.indicatorSection}>
            <div className={s.indicatorLabel}>Overlays</div>
            <div className={s.indicatorRow}>
              {INDICATORS.map((ind) => {
                const active = activeIndicators.includes(ind);
                const indColor = SMA_COLORS[ind] || colors.purple;
                return (
                  <button key={ind} onClick={() => toggleIndicator(ind)}
                    className={active ? s.indBtn : s.indBtnInactive}
                    style={active ? { background: indColor, color: '#0D1117', border: `1px solid ${indColor}` } : undefined}
                  >
                    {ind}
                  </button>
                );
              })}
            </div>
          </div>

          {/* Quick indicators — RSI, MACD, Bollinger, VWAP */}
          <div className={s.indicatorSection}>
            <div className={s.indicatorLabel}>Indicators</div>
            <div className={s.indicatorRow}>
              {QUICK_INDICATORS.map(({ id, label, color: indColor }) => {
                const active = activeIndicators.includes(id);
                return (
                  <button key={id} onClick={() => toggleIndicator(id)}
                    className={active ? s.indBtn : s.indBtnInactive}
                    style={active ? { background: indColor, color: '#0D1117', border: `1px solid ${indColor}` } : undefined}
                  >
                    {label}
                  </button>
                );
              })}
            </div>
          </div>

          {/* Signal overlay toggle */}
          <div className={s.indicatorSection}>
            <div className={s.indicatorLabel}>Signals {signals.length > 0 && `(${signals.length})`}</div>
            <div className={s.indicatorRow}>
              <button
                onClick={() => setShowSignals((v) => !v)}
                className={showSignals ? s.indBtn : s.indBtnInactive}
                style={showSignals ? { background: colors.green, color: '#0D1117', border: `1px solid ${colors.green}` } : undefined}
              >
                <svg width="10" height="10" viewBox="0 0 10 10" style={{ marginRight: 4, verticalAlign: 'middle' }}>
                  <polygon points="5,0 10,10 0,10" fill={showSignals ? '#0D1117' : colors.green} />
                </svg>
                Buy Signals
              </button>
              <button
                onClick={() => setShowSignals((v) => !v)}
                className={showSignals ? s.indBtn : s.indBtnInactive}
                style={showSignals ? { background: colors.red, color: '#0D1117', border: `1px solid ${colors.red}` } : undefined}
              >
                <svg width="10" height="10" viewBox="0 0 10 10" style={{ marginRight: 4, verticalAlign: 'middle' }}>
                  <polygon points="5,10 10,0 0,0" fill={showSignals ? '#0D1117' : colors.red} />
                </svg>
                Sell Signals
              </button>
              {signals.length === 0 && (
                <span style={{ fontSize: 11, color: colors.textSecondary, paddingLeft: 4 }}>No signals in 30d</span>
              )}
            </div>
          </div>

          {/* OHLCV display bar (desktop) */}
          {lastBar && !isMobile && (
            <div className={s.ohlcvBar}>
              {[
                { label: 'Open', value: (Number(lastBar.open) || 0).toFixed(2), color: colors.textPrimary },
                { label: 'High', value: (Number(lastBar.high) || 0).toFixed(2), color: colors.green },
                { label: 'Low', value: (Number(lastBar.low) || 0).toFixed(2), color: colors.red },
                { label: 'Close', value: (Number(lastBar.close) || 0).toFixed(2), color: (Number(lastBar.close) || 0) >= (Number(lastBar.open) || 0) ? colors.green : colors.red },
                { label: 'Volume', value: Number(lastBar.volume).toLocaleString(), color: colors.blue },
              ].map(({ label, value, color }) => (
                <div key={label} className={s.ohlcvItem}>
                  <div className={s.ohlcvLabel}>{label}</div>
                  <div className={s.ohlcvValue} style={{ color }}>
                    {label === 'Volume' ? value : `$${value}`}
                  </div>
                </div>
              ))}
            </div>
          )}
        </>
      )}
    </div>
  );
}
