/**
 * ChartToolbar — Unified toolbar for the advanced charting experience.
 *
 * Contains:
 * - Timeframe selector with keyboard shortcut hints
 * - Indicator quick-toggle pills
 * - Drawing tools (delegated to DrawingToolsPanel)
 * - Layout selector (1/2/4 panels)
 * - Fullscreen toggle
 * - S/R and Volume Profile toggles
 * - Auto-refresh toggle
 */
import { useState, memo } from 'react';
import { tokens } from '../../styles/tokens';

const C = {
  bg: '#0D1117',
  surface: '#161B22',
  surface2: '#1C2128',
  border: '#30363D',
  text: '#E6EDF3',
  muted: '#8B949E',
  green: '#3FB950',
  red: '#F85149',
  blue: '#58A6FF',
  amber: '#D29922',
  purple: '#BC8CFF',
  cyan: '#06B6D4',
};

const mono = "'JetBrains Mono', 'SF Mono', monospace";

const TIMEFRAMES = [
  { id: '1m', label: '1m', shortcut: '1' },
  { id: '5m', label: '5m', shortcut: '2' },
  { id: '15m', label: '15m', shortcut: '3' },
  { id: '1h', label: '1H', shortcut: '4' },
  { id: '4h', label: '4H', shortcut: '5' },
  { id: '1D', label: '1D', shortcut: '6' },
  { id: '1W', label: '1W', shortcut: '7' },
];

const INDICATOR_PILLS = [
  { id: 'SMA 20', label: 'SMA', color: C.blue, group: 'overlay' },
  { id: 'EMA 12', label: 'EMA', color: C.purple, group: 'overlay' },
  { id: 'BB 20', label: 'BB', color: C.amber, group: 'overlay' },
  { id: 'VWAP', label: 'VWAP', color: '#EC4899', group: 'overlay' },
  { id: 'RSI 14', label: 'RSI', color: C.amber, group: 'panel' },
  { id: 'MACD', label: 'MACD', color: C.green, group: 'panel' },
];

const LAYOUTS = [
  { id: 1, label: '1', cols: 1, rows: 1 },
  { id: 2, label: '2', cols: 2, rows: 1 },
  { id: 4, label: '4', cols: 2, rows: 2 },
];

/* ── Layout icon SVG ──────────────────────────────────────────────── */
function LayoutIcon({ cols, rows, active }) {
  const size = 16;
  const pad = 1;
  const gap = 1.5;
  const cellW = (size - pad * 2 - gap * (cols - 1)) / cols;
  const cellH = (size - pad * 2 - gap * (rows - 1)) / rows;
  const rects = [];
  for (let r = 0; r < rows; r++) {
    for (let c = 0; c < cols; c++) {
      rects.push(
        <rect
          key={`${r}-${c}`}
          x={pad + c * (cellW + gap)}
          y={pad + r * (cellH + gap)}
          width={cellW}
          height={cellH}
          rx={1}
          stroke="currentColor"
          strokeWidth="1.2"
          fill="none"
        />
      );
    }
  }
  return <svg width={size} height={size} viewBox={`0 0 ${size} ${size}`}>{rects}</svg>;
}

function ChartToolbar({
  timeframe = '1D',
  onTimeframeChange,
  activeIndicators = [],
  onToggleIndicator,
  activeLayout = 1,
  onLayoutChange,
  isFullscreen = false,
  onFullscreenToggle,
  showSR = false,
  onToggleSR,
  showVP = false,
  onToggleVP,
  showSignals = true,
  onToggleSignals,
  signalCount = 0,
  onScreenshot,
  onCompare,
  compareSymbol,
}) {
  const [showIndicatorDropdown, setShowIndicatorDropdown] = useState(false);

  return (
    <div style={{
      display: 'flex',
      alignItems: 'center',
      gap: 4,
      padding: '6px 12px',
      background: C.surface,
      borderBottom: `1px solid ${C.border}`,
      flexWrap: 'wrap',
      minHeight: 38,
    }}>
      {/* ── Timeframe selector ─────────────────────────────────────── */}
      <div style={{ display: 'flex', gap: 2, marginRight: 8 }}>
        {TIMEFRAMES.map((tf) => (
          <button
            key={tf.id}
            onClick={() => onTimeframeChange?.(tf.id)}
            title={`${tf.label} [${tf.shortcut}]`}
            style={{
              padding: '3px 7px',
              borderRadius: 4,
              border: 'none',
              fontFamily: mono,
              fontSize: 10,
              fontWeight: timeframe === tf.id ? 700 : 500,
              cursor: 'pointer',
              transition: 'all 0.12s',
              background: timeframe === tf.id ? C.blue : 'transparent',
              color: timeframe === tf.id ? C.bg : C.muted,
            }}
          >
            {tf.label}
          </button>
        ))}
      </div>

      {/* ── Divider ────────────────────────────────────────────────── */}
      <div style={{ width: 1, height: 18, background: C.border, margin: '0 4px', flexShrink: 0 }} />

      {/* ── Indicator pills ────────────────────────────────────────── */}
      <div style={{ display: 'flex', gap: 2, position: 'relative' }}>
        {INDICATOR_PILLS.map((ind) => {
          const active = activeIndicators.includes(ind.id);
          return (
            <button
              key={ind.id}
              onClick={() => onToggleIndicator?.(ind.id)}
              title={ind.id}
              style={{
                padding: '3px 7px',
                borderRadius: 4,
                border: `1px solid ${active ? ind.color : 'transparent'}`,
                fontFamily: mono,
                fontSize: 10,
                fontWeight: 600,
                cursor: 'pointer',
                transition: 'all 0.12s',
                background: active ? `${ind.color}20` : 'transparent',
                color: active ? ind.color : C.muted,
              }}
            >
              {ind.label}
            </button>
          );
        })}

        {/* More indicators dropdown */}
        <button
          onClick={() => setShowIndicatorDropdown(prev => !prev)}
          title="More indicators"
          style={{
            padding: '3px 7px',
            borderRadius: 4,
            border: 'none',
            fontFamily: mono,
            fontSize: 10,
            fontWeight: 600,
            cursor: 'pointer',
            background: showIndicatorDropdown ? `${C.blue}20` : 'transparent',
            color: C.muted,
          }}
        >
          +
        </button>

        {showIndicatorDropdown && (
          <div style={{
            position: 'absolute',
            top: '100%',
            left: 0,
            marginTop: 4,
            background: C.surface,
            border: `1px solid ${C.border}`,
            borderRadius: 8,
            padding: 8,
            zIndex: 100,
            boxShadow: '0 8px 24px rgba(0,0,0,0.5)',
            minWidth: 200,
          }}>
            <div style={{ fontSize: 10, fontWeight: 700, color: C.muted, marginBottom: 6, fontFamily: mono }}>
              ADDITIONAL OVERLAYS
            </div>
            {['SMA 8', 'SMA 21', 'SMA 50', 'SMA 200', 'EMA 9', 'EMA 20', 'EMA 21', 'EMA 26'].map((ind) => {
              const active = activeIndicators.includes(ind);
              return (
                <button
                  key={ind}
                  onClick={() => onToggleIndicator?.(ind)}
                  style={{
                    display: 'block',
                    width: '100%',
                    textAlign: 'left',
                    padding: '5px 10px',
                    background: active ? `${C.blue}15` : 'none',
                    border: 'none',
                    borderRadius: 4,
                    fontFamily: mono,
                    fontSize: 11,
                    color: active ? C.blue : C.text,
                    cursor: 'pointer',
                    marginBottom: 2,
                  }}
                  onMouseEnter={(e) => { e.target.style.background = C.surface2; }}
                  onMouseLeave={(e) => { e.target.style.background = active ? `${C.blue}15` : 'none'; }}
                >
                  {active ? '\u2713 ' : ''}{ind}
                </button>
              );
            })}
          </div>
        )}
      </div>

      {/* ── Divider ────────────────────────────────────────────────── */}
      <div style={{ width: 1, height: 18, background: C.border, margin: '0 4px', flexShrink: 0 }} />

      {/* ── S/R toggle ─────────────────────────────────────────────── */}
      <button
        onClick={onToggleSR}
        title="Support/Resistance [S]"
        style={{
          padding: '3px 7px',
          borderRadius: 4,
          border: `1px solid ${showSR ? C.green : 'transparent'}`,
          fontFamily: mono,
          fontSize: 10,
          fontWeight: 600,
          cursor: 'pointer',
          background: showSR ? 'rgba(63,185,80,0.15)' : 'transparent',
          color: showSR ? C.green : C.muted,
        }}
      >
        S/R
      </button>

      {/* ── VP toggle ──────────────────────────────────────────────── */}
      <button
        onClick={onToggleVP}
        title="Volume Profile [V]"
        style={{
          padding: '3px 7px',
          borderRadius: 4,
          border: `1px solid ${showVP ? C.blue : 'transparent'}`,
          fontFamily: mono,
          fontSize: 10,
          fontWeight: 600,
          cursor: 'pointer',
          background: showVP ? 'rgba(88,166,255,0.15)' : 'transparent',
          color: showVP ? C.blue : C.muted,
        }}
      >
        VP
      </button>

      {/* ── Signals toggle ─────────────────────────────────────────── */}
      <button
        onClick={onToggleSignals}
        title="Signal overlays"
        style={{
          display: 'flex',
          alignItems: 'center',
          gap: 3,
          padding: '3px 7px',
          borderRadius: 4,
          border: `1px solid ${showSignals ? C.green : 'transparent'}`,
          fontFamily: mono,
          fontSize: 10,
          fontWeight: 600,
          cursor: 'pointer',
          background: showSignals ? 'rgba(63,185,80,0.12)' : 'transparent',
          color: showSignals ? C.green : C.muted,
        }}
      >
        <svg width="8" height="8" viewBox="0 0 10 10"><polygon points="5,0 10,10 0,10" fill="currentColor" /></svg>
        {signalCount > 0 ? signalCount : ''}
      </button>

      <div style={{ flex: 1 }} />

      {/* ── Screenshot ─────────────────────────────────────────────── */}
      {onScreenshot && (
        <button
          onClick={onScreenshot}
          title="Save chart as PNG"
          style={{
            padding: '3px 6px',
            borderRadius: 4,
            border: 'none',
            background: 'transparent',
            color: C.muted,
            cursor: 'pointer',
            display: 'flex',
            alignItems: 'center',
          }}
        >
          <svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round">
            <rect x="3" y="3" width="18" height="18" rx="2" /><circle cx="8.5" cy="8.5" r="1.5" />
            <path d="M21 15l-5-5L5 21" />
          </svg>
        </button>
      )}

      {/* ── Layout selector ────────────────────────────────────────── */}
      <div style={{ display: 'flex', gap: 2 }}>
        {LAYOUTS.map((layout) => (
          <button
            key={layout.id}
            onClick={() => onLayoutChange?.(layout.id)}
            title={`${layout.label} chart${layout.id > 1 ? 's' : ''}`}
            style={{
              display: 'flex',
              alignItems: 'center',
              justifyContent: 'center',
              width: 26,
              height: 24,
              borderRadius: 4,
              border: 'none',
              background: activeLayout === layout.id ? C.blue : 'transparent',
              color: activeLayout === layout.id ? C.bg : C.muted,
              cursor: 'pointer',
              transition: 'all 0.12s',
            }}
          >
            <LayoutIcon cols={layout.cols} rows={layout.rows} active={activeLayout === layout.id} />
          </button>
        ))}
      </div>

      {/* ── Fullscreen ─────────────────────────────────────────────── */}
      <button
        onClick={onFullscreenToggle}
        title={`${isFullscreen ? 'Exit' : 'Enter'} fullscreen [F]`}
        style={{
          display: 'flex',
          alignItems: 'center',
          justifyContent: 'center',
          width: 26,
          height: 24,
          borderRadius: 4,
          border: 'none',
          background: isFullscreen ? C.blue : 'transparent',
          color: isFullscreen ? C.bg : C.muted,
          cursor: 'pointer',
          marginLeft: 4,
        }}
      >
        {isFullscreen ? (
          <svg width="14" height="14" viewBox="0 0 16 16" fill="none" stroke="currentColor" strokeWidth="1.5">
            <path d="M6 2H2v4M14 10v4h-4M10 14h4v-4M2 6V2h4" />
          </svg>
        ) : (
          <svg width="14" height="14" viewBox="0 0 16 16" fill="none" stroke="currentColor" strokeWidth="1.5">
            <path d="M2 6V2h4M14 10v4h-4M10 2h4v4M2 10v4h4" />
          </svg>
        )}
      </button>
    </div>
  );
}

export default memo(ChartToolbar);
