const COLORS = {
  sma: '#3B82F6', // blue
  ema: '#8B5CF6', // purple
  rsi: '#F59E0B', // amber
  macd: '#22C55E', // green
  bollinger: '#06B6D4', // cyan
  vwap: '#EC4899', // pink
  atr: '#EF4444', // red
};

const NAMES = {
  sma: 'SMA',
  ema: 'EMA',
  rsi: 'RSI',
  macd: 'MACD',
  bollinger: 'Bollinger Bands',
  vwap: 'VWAP',
  atr: 'ATR',
};

const PARAMS = {
  sma: ['period'],
  ema: ['period'],
  rsi: ['period'],
  macd: [],
  bollinger: ['period', 'stdDev'],
  vwap: [],
  atr: ['period'],
};

const IndicatorPanel = ({
  activeIndicators = {},
  onToggle = () => {},
  onParamChange = () => {},
  collapsed,
  onCollapse = () => {},
}) => {
  const panelWidth = collapsed ? 40 : 220;
  const labelFont = "'Plus Jakarta Sans', sans-serif";
  const dataFont = "'JetBrains Mono', monospace";

  return (
    <div
      style={{
        width: panelWidth,
        backgroundColor: '#0F1620',
        borderRight: '1px solid #1F2A37',
        color: '#E5E7DB',
        fontFamily: labelFont,
        display: 'flex',
        flexDirection: 'column',
        userSelect: 'none',
        transition: 'width 0.25s ease',
        overflow: 'hidden',
        height: '100%',
      }}
    >
      <button
        onClick={onCollapse}
        aria-label={collapsed ? 'Expand indicators panel' : 'Collapse indicators panel'}
        style={{
          height: 40,
          width: '100%',
          backgroundColor: '#111A24',
          border: 'none',
          borderBottom: '1px solid #1F2A37',
          color: '#90A3AF',
          fontSize: 14,
          cursor: 'pointer',
          fontFamily: labelFont,
          display: 'flex',
          alignItems: 'center',
          justifyContent: collapsed ? 'center' : 'space-between',
          padding: collapsed ? 0 : '0 12px',
        }}
        type="button"
      >
        {!collapsed && <span>Indicators</span>}
        <svg
          style={{
            transform: collapsed ? 'rotate(180deg)' : 'none',
            transition: 'transform 0.25s ease',
          }}
          xmlns="http://www.w3.org/2000/svg"
          width="16"
          height="16"
          fill="none"
          stroke="#90A3AF"
          strokeWidth="2"
          strokeLinecap="round"
          strokeLinejoin="round"
          viewBox="0 0 24 24"
          aria-hidden="true"
          focusable="false"
        >
          <polyline points="6 9 12 15 18 9" />
        </svg>
      </button>

      <div
        style={{
          flexGrow: 1,
          overflowY: 'auto',
          padding: collapsed ? 4 : 8,
        }}
      >
        {Object.entries(activeIndicators).map(([key, config]) => {
          const enabled = !!config.enabled;
          const params = PARAMS[key] || [];
          const color = COLORS[key] || '#888';

          return (
            <div
              key={key}
              style={{
                display: 'flex',
                flexDirection: 'column',
                marginBottom: collapsed ? 8 : 12,
                cursor: 'default',
              }}
            >
              <div
                style={{
                  display: 'flex',
                  alignItems: 'center',
                  gap: collapsed ? 0 : 8,
                  justifyContent: collapsed ? 'center' : 'flex-start',
                }}
              >
                {/* Color dot */}
                <div
                  style={{
                    width: 12,
                    height: 12,
                    borderRadius: 6,
                    backgroundColor: color,
                    flexShrink: 0,
                  }}
                  aria-hidden="true"
                />
                {!collapsed && (
                  <>
                    {/* Name label */}
                    <span
                      style={{
                        flexGrow: 1,
                        fontSize: 14,
                        color: '#E5E7DB',
                        fontFamily: labelFont,
                        userSelect: 'none',
                      }}
                    >
                      {NAMES[key]}
                    </span>

                    {/* Toggle switch */}
                    <button
                      type="button"
                      onClick={() => onToggle(key)}
                      aria-pressed={enabled}
                      aria-label={`${enabled ? 'Disable' : 'Enable'} ${NAMES[key]}`}
                      style={{
                        width: 36,
                        height: 20,
                        borderRadius: 10,
                        border: enabled ? 'none' : '1.5px solid #90A3AF',
                        backgroundColor: enabled ? '#22C55E' : 'transparent',
                        position: 'relative',
                        cursor: 'pointer',
                        padding: 0,
                        flexShrink: 0,
                        transition: 'background-color 0.25s ease, border-color 0.25s ease',
                      }}
                    >
                      <span
                        style={{
                          position: 'absolute',
                          top: 2,
                          left: enabled ? 18 : 2,
                          width: 16,
                          height: 16,
                          borderRadius: 10,
                          backgroundColor: '#0F1620',
                          transition: 'left 0.25s ease',
                        }}
                      />
                    </button>
                  </>
                )}
              </div>

              {!collapsed && enabled && params.length > 0 && (
                <div
                  style={{
                    marginTop: 8,
                    display: 'flex',
                    gap: 8,
                    flexWrap: 'wrap',
                  }}
                >
                  {params.map((paramKey) => {
                    const val = config[paramKey];
                    const labelText = paramKey === 'stdDev' ? 'Std Dev' : paramKey.charAt(0).toUpperCase() + paramKey.slice(1);
                    return (
                      <label
                        key={paramKey}
                        htmlFor={`${key}-${paramKey}`}
                        style={{
                          display: 'flex',
                          flexDirection: 'column',
                          fontSize: 11,
                          color: '#90A3AF',
                          userSelect: 'none',
                          minWidth: 48,
                        }}
                      >
                        <span
                          style={{
                            fontFamily: labelFont,
                            marginBottom: 4,
                          }}
                        >
                          {labelText}
                        </span>
                        <input
                          id={`${key}-${paramKey}`}
                          type="number"
                          min={paramKey === 'stdDev' ? 0 : 1}
                          step={paramKey === 'stdDev' ? 0.1 : 1}
                          value={val}
                          onChange={(e) => {
                            const v = paramKey === 'stdDev' ? parseFloat(e.target.value) : parseInt(e.target.value, 10);
                            if (!isNaN(v)) {
                              onParamChange(key, paramKey, v);
                            }
                          }}
                          style={{
                            fontFamily: dataFont,
                            fontSize: 13,
                            padding: '2px 6px',
                            borderRadius: 6,
                            border: '1px solid #1F2A37',
                            backgroundColor: '#111A24',
                            color: '#E5E7DB',
                            outline: 'none',
                            textAlign: 'center',
                            appearance: 'textfield',
                            MozAppearance: 'textfield',
                            WebkitAppearance: 'textfield',
                            userSelect: 'text',
                          }}
                          aria-label={`${NAMES[key]} ${labelText} parameter`}
                        />
                      </label>
                    );
                  })}
                </div>
              )}
            </div>
          );
        })}
      </div>
    </div>
  );
};

export default IndicatorPanel;
